/* ──────────────────────────────────────────────────────────────────────────
 * Lookup helpers
 * Each returns { btCode, qbAccount } or null if no mapping found.
 * ────────────────────────────────────────────────────────────────────────── */

function qbForTrade(tradeKey){
  if(!tradeKey) return null;
  const t = STMC_TRADE_MAP[tradeKey];
  return t ? { btCode: t.btCode, qbAccount: t.qbAccount } : null;
}

function qbForContractorLine(itemKey){
  if(!itemKey) return null;
  const c = STMC_CTR_MAP[itemKey];
  return c ? { btCode: c.btCode, qbAccount: c.qbAccount } : null;
}

function qbForUpgrade(itemId, fallbackTrade){
  if(itemId){
    const u = STMC_UPG_MAP[itemId];
    if(u && u.btCode) return { btCode: u.btCode, qbAccount: u.qbAccount };
  }
  // Pill 5 custom upgrades inherit from the user-selected trade
  return qbForTrade(fallbackTrade);
}

function qbForOther(budgetItem){
  if(!budgetItem) return null;
  const o = STMC_OTHER_MAP[budgetItem];
  return o ? { btCode: o.btCode, qbAccount: o.qbAccount } : null;
}

function qbValidate(qbAccount){
  /* Returns true if qbAccount is in the master account list. */
  return qbAccount && STMC_QB_ACCOUNTS.indexOf(qbAccount) >= 0;
}

/* Stamp a budget line in-place with btCode + qbAccount based on what it carries.
 * Priority: explicit itemKey (CTR) > explicit itemId (UPG) > tradeKey > otherItem.
 * Returns the same line for chaining.  */
function qbStampLine(line){
  if(!line) return line;
  let m = null;
  if(line.ctrItemKey)       m = qbForContractorLine(line.ctrItemKey);
  else if(line.upgItemId)   m = qbForUpgrade(line.upgItemId, line.tradeKey);
  else if(line.tradeKey)    m = qbForTrade(line.tradeKey);
  else if(line.otherItem)   m = qbForOther(line.otherItem);
  if(m){ line.btCode = m.btCode; line.qbAccount = m.qbAccount; }
  return line;
}


