/* ═══════════════════════════════════════════════════════════════
   MODEL NAME NORMALIZATION — run ONCE at page load.
   Canonical names come from V8 PM (exterior data is always required).
   We merge alias keys into the canonical keys across every object.
   ═══════════════════════════════════════════════════════════════ */
var MODEL_ALIASES = {
  "BERKLEY":              "THE BERKLEY",
  "DAUGHTERY":            "DAUGHERTY",
  "EAST FORK":            "EAST FORK DELUXE",
  "FOX RUN":              "FOX RUN BARNDOMINIUM",
  "HADLEY":               "THE HADLEY",
  "PETTUS":               "THE PETTUS",
  "SHADY MEADOW":         "SHADY MEADOWS",
  "THE SOUTHERN MONITOR": "SOUTHERN MONITOR",
  "TIMBERCREST":          "TIMBER CREST",
  "WOODSIDE SPECIAL 2.0": "WOODSIDE SPECIAL DELUXE"
};

function canonicalModel(m){ return (m && MODEL_ALIASES[m]) ? MODEL_ALIASES[m] : m; }

function normalizeObjectKeys(obj){
  // Null guard — some model-keyed tables may not be defined at the moment
  // applyModelAliases runs (e.g., MODELS/CRAFTSMAN before their script block
  // executes, or PDF_FILES if the file wasn't bundled). Skip silently.
  if(!obj || typeof obj !== "object") return;
  // For each alias key in obj, move its value to the canonical key, unless the canonical
  // key already has data (in which case we keep existing and delete the alias duplicate).
  Object.keys(MODEL_ALIASES).forEach(function(alias){
    if(Object.prototype.hasOwnProperty.call(obj, alias)){
      var canon = MODEL_ALIASES[alias];
      if(!Object.prototype.hasOwnProperty.call(obj, canon)){
        obj[canon] = obj[alias];
      }
      delete obj[alias];
    }
  });
}

function applyModelAliases(){
  // All model-keyed data objects get normalized to the canonical spelling.
  // Extended in 5.4 to cover P10, PM, MD, RD, PRESET_LABOR, MFT_PCT so
  // alias entries (e.g. "PETTUS" → "THE PETTUS") are unified across every
  // table that keys by model name. Previously only a subset was normalized,
  // which left PETTUS data orphaned between "PETTUS" (in P10/PM/MD/...) and
  // "THE PETTUS" (in INT_CONTRACT_REMOTE/MFT_PCT) — a Morristown Pettus
  // turnkey returned $0 interior contract silently.
  [P10, PM, MD, RD, PRESET_LABOR, MFT_PCT,
   PLAN_METRICS, INT_CONTRACT, INT_CONTRACT_REMOTE, BASE_COSTS,
   MODELS, CRAFTSMAN, PDF_FILES, CT_BASE_SF, CT_TIER_DATA].forEach(normalizeObjectKeys);
  // LIBERTY GROVE exists only in INT_CONTRACTS_APP data — no exterior data — drop it.
  // (User directive: canonical list is 40 names = 39 preset from PM + CUSTOM FLOOR PLAN)
  ["LIBERTY GROVE"].forEach(function(m){
    if(MODELS[m]) delete MODELS[m];
    if(PDF_FILES[m]) delete PDF_FILES[m];
    if(CRAFTSMAN[m]) delete CRAFTSMAN[m];
  });
}

applyModelAliases();

/* CANONICAL_MODELS — the alphabetized list shown in the model dropdown.
   39 preset models from PM + CUSTOM FLOOR PLAN pinned at end. */
var CANONICAL_MODELS = Object.keys(PM).sort();
// Ensure CUSTOM FLOOR PLAN exists in MODELS (it was in INT App MODELS).
