  [
    {id:"pullOut",    lbl:"Trash Can / Spice Pull Out Insert", rate:350, ph:"Enter insert type (e.g. Trash Can, Spice Rack, etc.)"},
    {id:"drawerRoll", lbl:"Drawer / Roll Out / Tip Out Insert",    rate:275, ph:"Enter insert type (e.g. Drawer Roll Out, Tip Out, etc.)"},
    {id:"custom",     lbl:"Custom Cabinet Insert",                  rate:500, ph:"Enter insert type (e.g. Lazy Susan, Wine Rack, etc.)"}
  ].forEach(function(ins){
    var entry = cu.inserts[ins.id];
    var qty = pi(entry.qty);
    var cost = qty * ins.rate;
    h += '<div class="upg-row">';
    h +=   '<span class="upg-label"><strong>'+esc(ins.lbl)+'</strong> <span style="font-size:11px;color:var(--g500)">'+fmt(ins.rate)+' each</span></span>';
    h +=   stepperHTML("inserts."+ins.id+".qty", qty, "stepInsertQty");
    h +=   '<span class="upg-cost'+(cost===0?" zero":"")+'">'+(cost===0?"—":fmt(cost))+'</span>';
    h += '</div>';
    if(qty > 0){
      h += '<div style="margin:-2px 0 10px 0">';
      h +=   '<input class="inp" type="text" placeholder="'+esc(ins.ph)+'" value="'+esc(entry.note||"")+'" oninput="updInsertNote(\''+ins.id+'\', this.value)" style="width:100%;font-size:12px">';
      h += '</div>';
    }
  });
  h +=   '</div>';
  h += '</div>';

  // Section 5 — Laundry
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Section 5 · Laundry Room Upgrades</span><span class="badge" id="cabsec-5">'+fmt(cabT.laundryTotal)+'</span></div>';
