/* ── INIT: idempotent normalizer for STATE.sel ── */
function initSelState(){
  if(!STATE.sel) STATE.sel = {};
  ["docusign","electrical","plumbing","trim"].forEach(function(k){
    if(!STATE.sel[k]) STATE.sel[k] = {};
    var s = STATE.sel[k];
    if(!s.toggles) s.toggles = {};
    if(!s.qtys) s.qtys = {};
    if(!s.sfs) s.sfs = {};
    if(!s.lfs) s.lfs = {};
    if(!Array.isArray(s.customLines)) s.customLines = [];
  });
  if(!STATE.sel.docusign.gasType) STATE.sel.docusign.gasType = "";
  if(!Array.isArray(STATE.sel.trim.concreteFinishLines)) STATE.sel.trim.concreteFinishLines = [];
  // Shower calculator state
  if(!Array.isArray(STATE.sel.plumbing.showers)) STATE.sel.plumbing.showers = [];
  if(STATE.sel.plumbing.showerUpgrade === undefined) STATE.sel.plumbing.showerUpgrade = null;
  if(!STATE.sel.custom) STATE.sel.custom = {upgrades:[], credits:[]};
  if(!Array.isArray(STATE.sel.custom.upgrades)) STATE.sel.custom.upgrades = [];
  if(!Array.isArray(STATE.sel.custom.credits)) STATE.sel.custom.credits = [];
  // Migrate legacy _mat/_fix trade values → base trade + subType
  var legacyMap = {
    "flooring_mat":"flooring", "drywall_mat":"drywall", "paint_mat":"paint",
    "trim_mat":"trim", "doors_mat":"trim", "insulation_mat":"insulation",
    "hvac_mat":"hvac", "plumbing_fix":"plumbing"
  };
  function migrateTrade(r){
    if(!r.subType) r.subType = "both";
    if(legacyMap[r.trade]){ r.subType = "material"; r.trade = legacyMap[r.trade]; }
  }
  STATE.sel.custom.upgrades.forEach(migrateTrade);
  STATE.sel.custom.credits.forEach(migrateTrade);
  if(!STATE.selSubTab) STATE.selSubTab = "docusign";
}

/* ── Compute: one item's cost ── */
function computeSelItemCost(item, sel){
  if(!sel) return 0;
  if(item.type === "toggle"){
    return (sel.toggles && sel.toggles[item.id]) ? item.price : 0;
  }
  if(item.type === "qty"){
    var qty = pn(sel.qtys && sel.qtys[item.id]);
    var cost = qty * item.price;
    if(item.baseAddOn && qty > 0) cost += item.baseAddOn;
    return cost;
  }
  if(item.type === "sf"){
    return pn(sel.sfs && sel.sfs[item.id]) * item.price;
  }
  if(item.type === "lf"){
    return pn(sel.lfs && sel.lfs[item.id]) * item.price;
  }
  return 0;
}

/* ── Compute: one pill's total (for pills with SEL_DEFS) ── */
function computeSelPillTotal(pillKey, S){
  S = S || STATE;
  var defs = SEL_DEFS[pillKey];
  if(!defs || !defs.sections) return 0;
  if(!S.sel || !S.sel[pillKey]) return 0;
  var sel = S.sel[pillKey];
  var total = 0;
  defs.sections.forEach(function(sec){
    (sec.items || []).forEach(function(it){ total += computeSelItemCost(it, sel); });
    (sec.subsections || []).forEach(function(sub){
      (sub.items || []).forEach(function(it){ total += computeSelItemCost(it, sel); });
    });
    if(sec.type === "customLines"){
      (sel.customLines || []).forEach(function(r){ total += pn(r.amount); });
    }
    if(sec.type === "concreteFinishLines"){
      (sel.concreteFinishLines || []).forEach(function(r){ total += pn(r.rate) * pn(r.sqft); });
    }
    if(sec.type === "showerCalc"){
      total += computeAllShowersCost(S);
    }
  });
  return total;
}

/* ── Compute: Pill 5 Custom upgrades / credits ── */
function computeCustomUpgradesTotal(S){
  S = S || STATE;
  if(!S.sel || !S.sel.custom) return 0;
  var total = 0;
  (S.sel.custom.upgrades || []).forEach(function(r){
    if(r.pricing === "flat") total += pn(r.amount);
    else total += pn(r.rate) * pn(r.qty);
  });
  return total;
}

function getSelectionsUpgradesTotal(S){
  S = S || STATE;
  var total = 0;
  ["docusign","electrical","plumbing","trim"].forEach(function(k){
    total += computeSelPillTotal(k, S);
  });
  total += computeCustomUpgradesTotal(S);
  return total;
}

/* ═══════════════════════════════════════════════════════════════
   STEP 7 RENDERER
   ═══════════════════════════════════════════════════════════════ */
function renderStep7(){
  if(!STATE.int) initInteriorState();
  else applyIntMetrics();
  initCabUpgradesState();
  initSelState();

  var subTab = STATE.selSubTab || "docusign";
  var h = '';
  var totals = {
    docusign:   computeSelPillTotal("docusign"),
    electrical: computeSelPillTotal("electrical"),
    plumbing:   computeSelPillTotal("plumbing"),
    trim:       computeSelPillTotal("trim"),
    custom:     computeCustomUpgradesTotal() - getInteriorCreditsTotal()
  };

  // Pill header
  h += '<div class="card">';
  h +=   '<div class="sub-pills">';
  ["docusign","electrical","plumbing","trim","custom"].forEach(function(k){
    var lbl = {docusign:"Docusign Upgrades", electrical:"Electrical", plumbing:"Plumbing", trim:"Trim & Flooring", custom:"Custom"}[k];
    var tot = totals[k];
    var sign = (tot < 0) ? "−" : "";
    var absT = Math.abs(tot);
    h += '<button class="sub-pill'+(subTab===k?" active":"")+'" onclick="switchSelSubTab(\''+k+'\')">'+esc(lbl)+' <span class="sub-pill-badge" id="selpill-badge-'+k+'">'+sign+fmt(absT)+'</span></button>';
  });
  h +=   '</div>';
  h += '</div>';

  // Active pill content
  if(subTab === "custom") h += renderPill5Custom();
  else h += renderSelPill(subTab);

  // Cross-reference note (all pills except Custom)
  if(subTab !== "custom"){
    h += '<div class="card"><div class="card-pad"><div class="banner banner-info"><strong>Need to add a custom upgrade or credit?</strong> Go to the <strong>Custom</strong> pill above to add upgrades not listed here, or to credit items the customer is providing themselves.</div></div></div>';
  }

  document.getElementById("stepContainer").innerHTML = h;
}

function switchSelSubTab(tab){ STATE.selSubTab = tab; renderCurrentStep(); }

/* ── Render one of the config-driven pills (docusign, electrical, plumbing, trim) ── */
function renderSelPill(pillKey){
  var defs = SEL_DEFS[pillKey];
  var sel = STATE.sel[pillKey];
  var pillTotal = computeSelPillTotal(pillKey);
  var h = '';

  defs.sections.forEach(function(sec, secIdx){
    var secTotal = computeSelSectionTotal(sec, sel);
    h += '<div class="card">';
    h +=   '<div class="section-hdr"><span>Section '+(secIdx+1)+' · '+esc(sec.title)+'</span>'
         +   '<span class="badge" id="selsec-'+pillKey+'-'+secIdx+'" style="'+(secTotal>0?'':'display:none')+'">'+fmt(secTotal)+'</span>'
         + '</div>';
    h +=   '<div class="card-pad">';
    if(sec.header) h += '<div class="sec-title" style="margin-top:0"><span>'+esc(sec.header)+'</span></div>';

    if(sec.type === "radio"){
      h += renderRadioSection(pillKey, sec);
    } else if(sec.type === "customLines"){
      h += renderCustomLinesSection(pillKey);
    } else if(sec.type === "concreteFinishLines"){
      h += renderConcreteFinishSection(sec);
    } else if(sec.type === "showerCalc"){
      h += renderShowerCalcSection(sec, pillKey);
    } else {
      // Standard section with items or subsections
      (sec.items || []).forEach(function(it){ h += renderSelItem(it, pillKey); });
      (sec.subsections || []).forEach(function(sub){
        h += '<div style="margin-top:12px;padding-top:10px;border-top:1px solid var(--g200)">';
        h +=   '<div class="sec-title" style="margin-top:0"><span>'+esc(sub.heading)+'</span></div>';
        sub.items.forEach(function(it){ h += renderSelItem(it, pillKey); });
        h += '</div>';
      });
    }

    if(sec.note) h += '<div class="field-hint" style="margin-top:10px">'+esc(sec.note)+'</div>';
    h +=   '</div>';
    h += '</div>';
  });

  // Pill total bar
  h += '<div class="card">';
  h +=   '<div class="card-pad">';
  h +=     '<div class="total-bar"><span class="total-lbl">'+esc(defs.label.toUpperCase())+' TOTAL</span><span class="total-val" id="selpill-total-'+pillKey+'">'+fmt(pillTotal)+'</span></div>';
  h +=   '</div>';
  h += '</div>';

  return h;
}

function computeSelSectionTotal(sec, sel){
  var total = 0;
  (sec.items || []).forEach(function(it){ total += computeSelItemCost(it, sel); });
  (sec.subsections || []).forEach(function(sub){
    sub.items.forEach(function(it){ total += computeSelItemCost(it, sel); });
  });
  if(sec.type === "customLines") (sel.customLines || []).forEach(function(r){ total += pn(r.amount); });
  if(sec.type === "concreteFinishLines") (sel.concreteFinishLines || []).forEach(function(r){ total += pn(r.rate) * pn(r.sqft); });
  if(sec.type === "showerCalc"){
    // Shower calculator total + standalone tile items
    total += computeAllShowersCost();
  }
  return total;
}

function renderSelItem(item, pillKey){
  var sel = STATE.sel[pillKey];
  var cost = computeSelItemCost(item, sel);
  var costDisplay = cost === 0 ? "—" : fmt(cost);
  var costClass = cost === 0 ? " zero" : "";
  var costId = ' id="selcost-'+pillKey+'-'+item.id+'"';
  var h = '';

  if(item.type === "toggle"){
    var on = !!(sel.toggles && sel.toggles[item.id]);
    h += '<div class="upg-row">';
    h +=   '<label class="upg-label" style="display:flex;align-items:center;gap:10px;cursor:pointer">'
         +   '<input type="checkbox" '+(on?"checked":"")+' onchange="updSelToggle(\''+pillKey+'\', \''+item.id+'\', this.checked)">'
         +   '<strong>'+esc(item.label)+'</strong> <span style="font-size:11px;color:var(--g500)">'+fmt(item.price)+'</span>'
         + '</label>';
    h +=   '<span class="upg-cost'+costClass+'"'+costId+'>'+costDisplay+'</span>';
    h += '</div>';
  } else if(item.type === "qty"){
    var qty = pi(sel.qtys && sel.qtys[item.id]);
    var unit = item.unit || "each";
    var baseHint = item.baseAddOn ? ' + '+fmt(item.baseAddOn)+' flat when qty&gt;0' : '';
    h += '<div class="upg-row">';
    h +=   '<span class="upg-label"><strong>'+esc(item.label)+'</strong> <span style="font-size:11px;color:var(--g500)">'+fmt(item.price)+'/'+esc(unit)+baseHint+'</span></span>';
    h +=   stepperHTML("sel."+pillKey+"."+item.id, qty, "stepSelQty");
    h +=   '<span class="upg-cost'+costClass+'"'+costId+'>'+costDisplay+'</span>';
    h += '</div>';
  } else if(item.type === "sf" || item.type === "lf"){
    var bucket = item.type === "sf" ? "sfs" : "lfs";
    var val = pn(sel[bucket] && sel[bucket][item.id]);
    var unit = item.type.toUpperCase();
    h += '<div class="upg-row">';
    h +=   '<span class="upg-label"><strong>'+esc(item.label)+'</strong> <span style="font-size:11px;color:var(--g500)">'+fmtC(item.price)+'/'+unit+'</span></span>';
    h +=   '<input class="inp mono num" type="number" step="0.1" min="0" value="'+(val||"")+'" placeholder="0" oninput="updSelNum(\''+pillKey+'\', \''+item.id+'\', \''+item.type+'\', this.value)" style="max-width:140px">';
    h +=   '<span class="upg-cost'+costClass+'"'+costId+'>'+costDisplay+'</span>';
    h += '</div>';
  }
  return h;
}

function renderRadioSection(pillKey, sec){
  var cur = STATE.sel[pillKey][sec.id] || "";
  return radioPillsHTML("sel."+pillKey+"."+sec.id,
    sec.options.filter(function(o){ return o.v !== ""; }),
    cur, "updSelRadio");
}

function renderCustomLinesSection(pillKey){
  var lines = STATE.sel[pillKey].customLines || [];
  var h = '';
  if(lines.length > 0){
    h += '<div class="row-table">';
    h +=   '<div class="row-hdr" style="grid-template-columns:1.8fr 140px 36px"><div>Description</div><div style="text-align:right">Amount</div><div></div></div>';
    lines.forEach(function(r, i){
      h += '<div class="row-line" style="grid-template-columns:1.8fr 140px 36px">';
      h +=   '<input class="inp" type="text" value="'+esc(r.desc)+'" placeholder="Description" oninput="updSelCustomLine(\''+pillKey+'\', '+i+', \'desc\', this.value)">';
      h +=   '<input class="inp mono num" type="number" min="0" value="'+(pn(r.amount)||"")+'" placeholder="0" oninput="updSelCustomLine(\''+pillKey+'\', '+i+', \'amount\', this.value)">';
      h +=   '<button class="row-del" onclick="delSelCustomLine(\''+pillKey+'\', '+i+')">×</button>';
      h += '</div>';
    });
    h += '</div>';
  }
  h += '<div style="margin-top:10px"><button class="row-add" onclick="addSelCustomLine(\''+pillKey+'\')">+ Add Another Upgrade</button></div>';
  return h;
}

function renderConcreteFinishSection(sec){
  var lines = STATE.sel.trim.concreteFinishLines || [];
  var h = '';
  if(sec.referencePricing){
    h += '<div style="background:var(--g50);border:1px solid var(--g200);border-radius:var(--radius-sm);padding:10px 14px;margin-bottom:12px;font-size:12px">';
    h +=   '<div style="font-weight:600;color:var(--g700);margin-bottom:6px">Reference Pricing</div>';
    h +=   '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:4px 16px;color:var(--g600)">';
    sec.referencePricing.forEach(function(rp){
      h += '<div><span>'+esc(rp.l)+':</span> <span class="mono" style="color:var(--g900);font-weight:500">'+esc(rp.r)+'</span></div>';
    });
    h +=   '</div>';
    h += '</div>';
  }
  if(lines.length > 0){
    h += '<div class="row-table">';
    h +=   '<div class="row-hdr" style="grid-template-columns:1.6fr 120px 110px 110px 36px"><div>Description</div><div style="text-align:right">$/SF</div><div style="text-align:right">SF</div><div style="text-align:right">Cost</div><div></div></div>';
    lines.forEach(function(r, i){
      var cost = pn(r.rate) * pn(r.sqft);
      h += '<div class="row-line" style="grid-template-columns:1.6fr 120px 110px 110px 36px">';
      h +=   '<input class="inp" type="text" value="'+esc(r.desc)+'" placeholder="e.g. Grind & Seal — Living Area" oninput="updConcFinishLine('+i+', \'desc\', this.value)">';
      h +=   '<input class="inp mono num" type="number" step="0.01" min="0" value="'+(pn(r.rate)||"")+'" placeholder="0" oninput="updConcFinishLine('+i+', \'rate\', this.value)">';
      h +=   '<input class="inp mono num" type="number" min="0" value="'+(pn(r.sqft)||"")+'" placeholder="0" oninput="updConcFinishLine('+i+', \'sqft\', this.value)">';
      h +=   '<div class="row-cost" id="concfin-cost-'+i+'">'+(cost>0?fmt(cost):"—")+'</div>';
      h +=   '<button class="row-del" onclick="delConcFinishLine('+i+')">×</button>';
      h += '</div>';
    });
    h += '</div>';
  }
  h += '<div style="margin-top:10px"><button class="row-add" onclick="addConcFinishLine()">+ Add Another Line</button></div>';
  return h;
}

/* ═══════════════════════════════════════════════════════════════
   SHOWER CALCULATOR RENDERER
   Renders the gated shower calculator + standalone tile floor
   ═══════════════════════════════════════════════════════════════ */
function renderShowerCalcSection(sec, pillKey){
  var sel = STATE.sel.plumbing;
  var showers = sel.showers || [];
  var gate = sel.showerUpgrade; // null=unanswered, true, false
  var shTotal = computeAllShowersCost();
  var h = '';

  // Gate question
  h += '<div class="upg-row" style="padding:14px 16px;margin-bottom:14px;'+(gate===null||gate===undefined?'background:var(--amber-light);border-color:#FDE68A':'background:var(--g50)')+'">';
  h +=   '<span style="font-size:14px;font-weight:700;flex:1">Customer Tile Shower Upgrade?</span>';
  h +=   '<div style="display:flex;gap:8px">';
  h +=     '<button class="footer-btn" style="padding:8px 20px;font-weight:700;font-size:13px;'+(gate===true?'border-color:var(--green);background:var(--green-light);color:var(--green-dark)':'')+'" onclick="setShowerGate(true)">Yes</button>';
  h +=     '<button class="footer-btn" style="padding:8px 20px;font-weight:700;font-size:13px;'+(gate===false?'border-color:var(--red);background:var(--red-light);color:var(--red-dark)':'')+'" onclick="setShowerGate(false)">No</button>';
  h +=   '</div>';
  h += '</div>';

  if(gate === true){
    h += '<div class="banner banner-amber" style="font-size:12px"><strong>Standard tile height is up to 8\'.</strong> Heights above 8\' may require additional material and labor.</div>';

    showers.forEach(function(sh, idx){
      var c = computeShowerCost(sh);
      h += '<div style="border:1px solid var(--g200);border-radius:var(--radius);padding:16px;margin-bottom:12px">';
      // Header
      h +=   '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">';
      h +=     '<input class="inp" type="text" value="'+esc(sh.label)+'" style="border:none;border-bottom:2px solid var(--g200);border-radius:0;padding:4px 0;width:200px;font-size:15px;font-weight:700" oninput="updShowerField('+idx+',\'label\',this.value)">';
      h +=     '<div style="display:flex;align-items:center;gap:8px"><span style="font-family:var(--font-mono);font-weight:700;font-size:16px;color:var(--red)">'+fmt(Math.round(c.total))+'</span>';
      if(showers.length > 1) h += '<button class="row-del" style="width:28px;height:28px" onclick="delShower('+idx+')">×</button>';
      h +=     '</div>';
      h +=   '</div>';
      // Inputs: Base type + W + D + H
      h +=   '<div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:10px;margin-bottom:14px">';
      h +=     '<div><div class="sum-lbl" style="margin-bottom:4px">Base Type</div><select class="sel" style="font-size:13px;'+(sh.base==="tile"?"background:#FFF7ED":"")+'" onchange="updShowerField('+idx+',\'base\',this.value)"><option value="acrylic"'+(sh.base!=="tile"?" selected":"")+'>Acrylic</option><option value="tile"'+(sh.base==="tile"?" selected":"")+'>Tile</option></select></div>';
      h +=     '<div><div class="sum-lbl" style="margin-bottom:4px">Width (ft)</div><input class="inp mono" type="number" min="0" step="0.5" style="text-align:center;font-size:16px;font-weight:700" value="'+(sh.width||"")+'" placeholder="3" oninput="updShowerField('+idx+',\'width\',this.value)"></div>';
      h +=     '<div><div class="sum-lbl" style="margin-bottom:4px">Depth (ft)</div><input class="inp mono" type="number" min="0" step="0.5" style="text-align:center;font-size:16px;font-weight:700" value="'+(sh.depth||"")+'" placeholder="5" oninput="updShowerField('+idx+',\'depth\',this.value)"></div>';
      h +=     '<div><div class="sum-lbl" style="margin-bottom:4px">Height (ft)</div><input class="inp mono" type="number" min="0" step="0.5" style="text-align:center;font-size:16px;font-weight:700;'+(pn(sh.height)>8?'border-color:var(--amber)':'')+'" value="'+(sh.height||"")+'" placeholder="8" oninput="updShowerField('+idx+',\'height\',this.value)">';
      if(pn(sh.height) > 8) h += '<div style="font-size:10px;color:var(--amber-dark);margin-top:2px">Above std 8\'</div>';
      h +=     '</div>';
      h +=   '</div>';
      // Add-ons: Bench + Niche qty
      h +=   '<div style="display:flex;gap:12px;margin-bottom:14px">';
      h +=     '<div style="flex:1"><div class="sum-lbl" style="margin-bottom:4px">Bench ($'+SHOWER_BENCH_PRICE+' ea)</div><input class="inp mono" type="number" min="0" step="1" style="text-align:center;font-size:14px" value="'+(pi(sh.benchQty)||"")+'" placeholder="0" oninput="updShowerField('+idx+',\'benchQty\',this.value)"></div>';
      h +=     '<div style="flex:1"><div class="sum-lbl" style="margin-bottom:4px">Niche ($'+SHOWER_NICHE_PRICE+' ea)</div><input class="inp mono" type="number" min="0" step="1" style="text-align:center;font-size:14px" value="'+(pi(sh.nicheQty)||"")+'" placeholder="0" oninput="updShowerField('+idx+',\'nicheQty\',this.value)"></div>';
      h +=   '</div>';
      // Breakdown
      h +=   '<div style="background:var(--g50);border-radius:var(--radius-sm);padding:10px 14px;border:1px solid var(--g200)">';
      h +=     '<div class="sum-lbl" style="margin-bottom:8px">Breakdown</div>';
      h +=     '<div style="display:flex;justify-content:space-between;padding:5px 0;font-size:13px;border-bottom:1px solid var(--g100)"><span>Walls <span style="font-size:11px;color:var(--g500);font-family:var(--font-mono)">'+c.wallSF+' SF × $'+SHOWER_WALL_RATE.toFixed(4)+'/SF</span></span><span style="font-family:var(--font-mono);font-weight:600">'+fmtC(c.wallCost)+'</span></div>';
      h +=     '<div style="display:flex;justify-content:space-between;padding:5px 0;font-size:13px;border-bottom:1px solid var(--g100)"><span>Floor <span style="font-size:11px;color:var(--g500);font-family:var(--font-mono)">'+(sh.base==="tile"?c.floorSF+' SF × $'+SHOWER_FLOOR_RATE.toFixed(4)+'/SF':'Acrylic pan (included in wall rate)')+'</span></span><span style="font-family:var(--font-mono);font-weight:600">'+(sh.base==="tile"?fmtC(c.floorCost):'$0.00')+'</span></div>';
      if(c.benchCost > 0 || c.nicheCost > 0){
        var addonDesc = [];
        if(pi(sh.benchQty)>0) addonDesc.push(sh.benchQty+' bench × $'+SHOWER_BENCH_PRICE);
        if(pi(sh.nicheQty)>0) addonDesc.push(sh.nicheQty+' niche × $'+SHOWER_NICHE_PRICE);
        h += '<div style="display:flex;justify-content:space-between;padding:5px 0;font-size:13px;border-bottom:1px solid var(--g100)"><span>Add-Ons <span style="font-size:11px;color:var(--g500);font-family:var(--font-mono)">'+addonDesc.join(' + ')+'</span></span><span style="font-family:var(--font-mono);font-weight:600">'+fmtC(c.benchCost+c.nicheCost)+'</span></div>';
      }
      h +=     '<div style="display:flex;justify-content:space-between;padding:8px 0 0;margin-top:4px;border-top:2px solid var(--g300);font-weight:700"><span>TOTAL</span><span style="font-family:var(--font-mono);font-size:15px">'+fmtC(c.total)+'</span></div>';
      h +=   '</div>';
      // Contract note
      h +=   '<div style="margin-top:10px;padding:8px 12px;background:var(--g50);border:1px solid var(--g200);border-radius:var(--radius-sm);font-size:12px;color:var(--g700)"><strong style="color:var(--red)">Contract Note:</strong> '+esc(showerContractNote(sh))+'</div>';
      h += '</div>';
    });
    h += '<button class="row-add" onclick="addShower()" style="margin-bottom:14px">+ Add Another Shower</button>';
  }

  if(gate === false){
    h += '<div class="banner banner-empty" style="margin:0 0 14px">No tile shower upgrades. Standard shower package included.</div>';
  }

  // Standalone Tile Floor — ALWAYS visible
  h += '<div style="margin-top:14px;padding-top:14px;border-top:1px solid var(--g200)">';
  h +=   '<div class="sum-lbl" style="margin-bottom:8px">Standalone Tile (outside showers)</div>';
  (sec.items || []).forEach(function(it){ h += renderSelItem(it, pillKey); });
  h += '</div>';

  return h;
}

/* ── Pill 5 — Custom Upgrades & Credits ── */
function renderPill5Custom(){
  var cust = STATE.sel.custom;
  var upgrades = cust.upgrades || [];
  var credits = cust.credits || [];
  var upTotal = computeCustomUpgradesTotal();
  var crTotal = getInteriorCreditsTotal();
  var netCredits = Math.min(crTotal, upTotal);
  var intUpgrades = getInteriorUpgradesTotal();
  var overCap = crTotal > intUpgrades;
  var netVal = upTotal - netCredits;
  var h = '';

  // Instructions banner
  h += '<div class="card"><div class="card-pad">';
  h +=   '<div class="banner banner-info" style="line-height:1.7">';
  h +=     '<strong style="font-size:13px">Custom Upgrades & Credits — Quick Guide</strong><br><br>';
  h +=     'Use this section for anything not already listed on the other tabs. Pick the trade category, enter your pricing, and the budget adjusts automatically.<br><br>';
  h +=     '<strong style="color:var(--g900)">When to Add an Upgrade</strong><br>'
         + 'The customer wants something extra that STMC will provide or install.<br>'
         + '• <em>Whole-house water softener</em> → Category: <strong>Plumbing</strong>, Flat Rate, $1,800. Budget adds $1,440 (80%) to Plumbing.<br>'
         + '• <em>Upgraded baseboard — 7.25 inch throughout</em> → Category: <strong>Trim & Doors</strong>, Applies To: <strong>Material</strong>, Per LF, $4.50 × 320 LF. Budget adds $1,152 to Trim materials.<br>'
         + '• <em>Specialty tile accent wall in master bath</em> → Category: <strong>Tile</strong>, Per SF, $12 × 80 SF. Budget adds $768 to Tile.<br><br>';
  h +=     '<strong style="color:var(--g900)">When to Add a Credit</strong><br>'
         + 'The customer is providing something themselves, so we need to reduce the contract and the trade budget.<br>'
         + '• <em>Customer supplying their own LVP flooring, but STMC still installs it</em> → Category: <strong>Flooring</strong>, Applies To: <strong>Material</strong>, $3,400. This reduces ONLY the flooring material budget — install labor stays intact.<br>'
         + '• <em>Customer supplying all light fixtures</em> → Category: <strong>Lighting</strong>, $2,000. The contract drops by $2,000 and Lighting budget is reduced by the full amount.<br>'
         + '• <em>Customer hiring their own painter</em> → Category: <strong>Paint</strong>, Applies To: <strong>Labor</strong>, $4,500. Removes the paint labor budget — STMC still supplies the paint material.<br><br>';
  h +=     '<strong style="color:var(--g900)">Labor / Material / Both — When Does This Matter?</strong><br>'
         + 'For trades like Flooring, Trim, Paint, Plumbing, and Electrical, the budget has separate labor and material lines. '
         + 'After you pick one of these categories, a <strong>Labor / Material / Both</strong> toggle appears. This tells the PM exactly which budget line is affected.<br>'
         + '• Pick <strong>Material</strong> when the customer is providing the product but STMC still does the work.<br>'
         + '• Pick <strong>Labor</strong> when the customer has their own contractor but STMC is still providing the product.<br>'
         + '• Leave it on <strong>Both</strong> when the upgrade or credit applies to the whole trade (most common), or if you\'re not sure — it routes to the combined trade line.';
  h +=   '</div>';
  h += '</div></div>';

  // Part A — Custom Upgrades
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Part A · Custom Upgrades</span>'
       +   '<span class="badge" id="pill5-partA-badge">'+fmt(upTotal)+'</span>'
       + '</div>';
  h +=   '<div class="card-pad">';
  if(upgrades.length === 0){
    h += '<div class="banner banner-empty">No custom upgrades yet. Add upgrades not listed on other tabs.</div>';
  } else {
    upgrades.forEach(function(r, i){
      h += renderCustomUpgradeRow(r, i);
    });
  }
  h +=     '<div style="margin-top:10px"><button class="row-add" onclick="addCustomUpgrade()">+ Add Another Upgrade</button></div>';
  h +=   '</div>';
  h += '</div>';

  // Part B — Credits
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Part B · Credits</span>'
       +   '<span class="badge" id="pill5-partB-badge" style="background:'+(crTotal>0?"var(--amber-dark)":"")+';color:'+(crTotal>0?"#fff":"")+'">'+(crTotal>0?"−"+fmt(crTotal):"$0")+'</span>'
       + '</div>';
  h +=   '<div class="card-pad">';
  // Credit-cap warning banner — always rendered with display:none so refresh can toggle visibility
  var baseINTText = (STATE.model && !isCustomFloorPlan() && INT_CONTRACT[STATE.model]) ? fmt(INT_CONTRACT[STATE.model].t) : "the base turnkey price";
  h +=     '<div id="pill5-cap-warning" class="banner banner-amber" style="display:'+(overCap && STATE.model && !isCustomFloorPlan() ? "":"none")+'">'
         +   '⚠ Credits (<strong id="pill5-cap-creds">'+fmt(crTotal)+'</strong>) exceed total upgrades (<strong id="pill5-cap-upg">'+fmt(intUpgrades)+'</strong>). '
         +   'The adjusted INT Contract will not fall below the standard turnkey price of <strong>'+baseINTText+'</strong> for this model.'
         + '</div>';
  if(credits.length === 0){
    h += '<div class="banner banner-empty">No credits yet. Add credits for items the customer is providing themselves.</div>';
  } else {
    credits.forEach(function(r, i){
      h += renderCustomCreditRow(r, i);
    });
  }
  h +=     '<div style="margin-top:10px"><button class="row-add" onclick="addCustomCredit()">+ Add Another Credit</button></div>';
  h +=   '</div>';
  h += '</div>';

  // Net total
  h += '<div class="card"><div class="card-pad">';
  h +=   '<div class="total-bar" id="pill5-net-bar" style="'+(netVal<0?"background:var(--g800)":"")+'">'
       +   '<span class="total-lbl">CUSTOM NET TOTAL</span>'
       +   '<span class="total-val" id="pill5-net-total">'+(netVal<0?"−":"")+fmt(Math.abs(netVal))+'</span>'
       + '</div>';
  h += '<div id="pill5-split-line" style="margin-top:8px;font-size:12px;color:var(--g600);line-height:1.5;'+(crTotal===0?"display:none":"")+'">'
     +   'Upgrades: <span id="pill5-split-up">'+fmt(upTotal)+'</span> · Credits applied: <span id="pill5-split-cr">'+fmt(netCredits)+'</span>'
     +   '<span id="pill5-split-capnote" style="'+(netCredits<crTotal?"":"display:none")+'"> (capped from <span id="pill5-split-rawcr">'+fmt(crTotal)+'</span>)</span>'
     + '</div>';
  h += '</div></div>';

  return h;
}

function renderCustomUpgradeRow(r, i){
  var showSub = r.trade && tradeHasSub(r.trade);
  var h = '<div class="row-line" style="display:flex;flex-direction:column;gap:8px;background:var(--g50);margin-bottom:8px">';
  h +=   '<div style="display:flex;justify-content:space-between;align-items:center">';
  h +=     '<span style="font-size:11px;font-weight:600;color:var(--g500);text-transform:uppercase;letter-spacing:0.05em">Upgrade '+(i+1)+'</span>';
  h +=     '<button class="row-del" onclick="delCustomUpgrade('+i+')">×</button>';
  h +=   '</div>';
  // Row 1: Trade + optional subType + Pricing
  h +=   '<div class="field-row">';
  h +=     '<div class="field" style="min-width:200px"><label class="field-lbl">Category</label>'+customTradeDropdown(r.trade, "updCustomUpgrade", i, "trade")+'</div>';
  if(showSub){
    h +=   '<div class="field" style="min-width:200px"><label class="field-lbl">Applies To</label>'+subTypePills(r.subType||"both", "updCustomUpgrade", i)+'</div>';
  }
  h +=     '<div class="field"><label class="field-lbl">Pricing Type</label>';
  h +=       '<div class="radio-pills">';
  h +=         '<button class="radio-pill'+(r.pricing==="flat"?" active":"")+'" onclick="updCustomUpgrade('+i+', \'pricing\', \'flat\')">Flat Rate</button>';
  h +=         '<button class="radio-pill'+(r.pricing==="per_unit"?" active":"")+'" onclick="updCustomUpgrade('+i+', \'pricing\', \'per_unit\')">Per SF / LF</button>';
  h +=       '</div>';
  h +=     '</div>';
  h +=   '</div>';
  // Row 2: Fields based on pricing type
  if(r.pricing === "flat"){
    var cost = pn(r.amount);
    h += '<div class="field-row">';
    h +=   '<div class="field" style="flex:2"><label class="field-lbl">Description</label><input class="inp" type="text" value="'+esc(r.desc)+'" placeholder="e.g. Custom range hood install" oninput="updCustomUpgrade('+i+', \'desc\', this.value)"></div>';
    h +=   '<div class="field"><label class="field-lbl">Amount</label><input class="inp mono num" type="number" min="0" value="'+(pn(r.amount)||"")+'" placeholder="0" oninput="updCustomUpgrade('+i+', \'amount\', this.value)"></div>';
    h +=   '<div class="field" style="max-width:120px"><label class="field-lbl">Row Total</label><div class="metric-readout" id="custup-total-'+i+'">'+(cost>0?fmt(cost):"—")+'</div></div>';
    h += '</div>';
  } else {
    var cost = pn(r.rate) * pn(r.qty);
    h += '<div class="field-row">';
    h +=   '<div class="field" style="flex:2"><label class="field-lbl">Description</label><input class="inp" type="text" value="'+esc(r.desc)+'" placeholder="e.g. Specialty tile accent wall" oninput="updCustomUpgrade('+i+', \'desc\', this.value)"></div>';
    h +=   '<div class="field"><label class="field-lbl">Rate / Unit</label><input class="inp mono num" type="number" step="0.01" min="0" value="'+(pn(r.rate)||"")+'" placeholder="0" oninput="updCustomUpgrade('+i+', \'rate\', this.value)"></div>';
    h +=   '<div class="field" style="max-width:100px"><label class="field-lbl">Unit</label><select class="sel" onchange="updCustomUpgrade('+i+', \'unit\', this.value)"><option value="SF"'+(r.unit==="SF"?" selected":"")+'>SF</option><option value="LF"'+(r.unit==="LF"?" selected":"")+'>LF</option></select></div>';
    h +=   '<div class="field"><label class="field-lbl">Qty</label><input class="inp mono num" type="number" min="0" value="'+(pn(r.qty)||"")+'" placeholder="0" oninput="updCustomUpgrade('+i+', \'qty\', this.value)"></div>';
    h +=   '<div class="field" style="max-width:120px"><label class="field-lbl">Row Total</label><div class="metric-readout" id="custup-total-'+i+'">'+(cost>0?fmt(cost):"—")+'</div></div>';
    h += '</div>';
  }
  h += '</div>';
  return h;
}

function renderCustomCreditRow(r, i){
  var amt = pn(r.amount);
  var showSub = r.trade && tradeHasSub(r.trade);
  var h = '<div class="row-line" style="display:flex;flex-direction:column;gap:8px;background:#FEF3C7;border-color:#FDE68A;margin-bottom:8px">';
  h +=   '<div style="display:flex;justify-content:space-between;align-items:center">';
  h +=     '<span style="font-size:11px;font-weight:600;color:var(--amber-dark);text-transform:uppercase;letter-spacing:0.05em">Credit '+(i+1)+'</span>';
  h +=     '<button class="row-del" onclick="delCustomCredit('+i+')">×</button>';
  h +=   '</div>';
  h +=   '<div class="field-row">';
  h +=     '<div class="field" style="min-width:200px"><label class="field-lbl">Category</label>'+customTradeDropdown(r.trade, "updCustomCredit", i, "trade")+'</div>';
  if(showSub){
    h +=   '<div class="field" style="min-width:200px"><label class="field-lbl">Applies To</label>'+subTypePills(r.subType||"both", "updCustomCredit", i)+'</div>';
  }
  h +=     '<div class="field" style="flex:2"><label class="field-lbl">Description</label><input class="inp" type="text" value="'+esc(r.desc)+'" placeholder="e.g. Customer providing all light fixtures" oninput="updCustomCredit('+i+', \'desc\', this.value)"></div>';
  h +=     '<div class="field"><label class="field-lbl">Credit Amount</label><input class="inp mono num" type="number" min="0" value="'+(pn(r.amount)||"")+'" placeholder="0" oninput="updCustomCredit('+i+', \'amount\', this.value)"></div>';
  h +=     '<div class="field" style="max-width:120px"><label class="field-lbl">Applied</label><div class="metric-readout" id="custcr-total-'+i+'" style="color:var(--amber-dark)">'+(amt>0?"−"+fmt(amt):"—")+'</div></div>';
  h +=   '</div>';
  h += '</div>';
  return h;
}

function customTradeDropdown(cur, handler, i, field){
  var h = '<select class="sel" onchange="'+handler+'('+i+', \''+field+'\', this.value)">';
  h +=   '<option value=""'+(cur===""?" selected":"")+'>— Select Category —</option>';
  CUSTOM_TRADE_CATS.forEach(function(cat){
    h += '<option value="'+esc(cat.v)+'"'+(cur===cat.v?" selected":"")+'>'+esc(cat.l)+'</option>';
  });
  h += '</select>';
  return h;
}

function tradeHasSub(tradeVal){
  for(var i=0; i<CUSTOM_TRADE_CATS.length; i++){
    if(CUSTOM_TRADE_CATS[i].v === tradeVal) return CUSTOM_TRADE_CATS[i].hasSub;
  }
  return false;
}

function subTypePills(curSub, handler, rowIdx){
  var h = '<div class="radio-pills" style="margin-top:0">';
  ["labor","material","both"].forEach(function(v){
    var lbl = v === "labor" ? "Labor" : v === "material" ? "Material" : "Both";
    h += '<button class="radio-pill'+(curSub===v?" active":"")+'" onclick="'+handler+'('+rowIdx+', \'subType\', \''+v+'\')">'+lbl+'</button>';
  });
  h += '</div>';
  return h;
}

/* ═══════════════════════════════════════════════════════════════
   STEP 7 HANDLERS
   ═══════════════════════════════════════════════════════════════ */
/* ═══════════════════════════════════════════════════════════════
   STEP 7 LIVE REFRESH — targeted DOM updates without rebuilding inputs
   Called by oninput handlers so per-row costs update on every keystroke
   without losing cursor focus.
   ═══════════════════════════════════════════════════════════════ */
function refreshStep7Live(){
  // 1. Update per-item cost spans on pills 1-4 (ID: selcost-{pillKey}-{itemId})
  ["docusign","electrical","plumbing","trim"].forEach(function(pillKey){
    var sel = STATE.sel[pillKey];
    if(!sel) return;
    var defs = SEL_DEFS[pillKey];
    defs.sections.forEach(function(sec){
      function updateItem(it){
        var cost = computeSelItemCost(it, sel);
        var span = document.getElementById("selcost-"+pillKey+"-"+it.id);
        if(span){
          span.textContent = cost === 0 ? "—" : fmt(cost);
          if(cost === 0) span.classList.add("zero");
          else span.classList.remove("zero");
        }
      }
      (sec.items || []).forEach(updateItem);
      (sec.subsections || []).forEach(function(sub){ sub.items.forEach(updateItem); });
    });
  });

  // 2. Update concrete finish row costs (ID: concfin-cost-{i})
  (STATE.sel.trim.concreteFinishLines || []).forEach(function(r, i){
    var cost = pn(r.rate) * pn(r.sqft);
    var el = document.getElementById("concfin-cost-"+i);
    if(el) el.textContent = cost > 0 ? fmt(cost) : "—";
  });

  // 3. Update section badges on the active pill (ID: selsec-{pillKey}-{secIdx})
  var activePill = STATE.selSubTab;
  if(activePill && activePill !== "custom"){
    var defs = SEL_DEFS[activePill];
    var sel = STATE.sel[activePill];
    defs.sections.forEach(function(sec, i){
      var total = computeSelSectionTotal(sec, sel);
      var badge = document.getElementById("selsec-"+activePill+"-"+i);
      if(badge){
        badge.textContent = fmt(total);
        badge.style.display = total > 0 ? "" : "none";
      }
    });
    // Update pill total bar
    var totalBar = document.getElementById("selpill-total-"+activePill);
    if(totalBar) totalBar.textContent = fmt(computeSelPillTotal(activePill));
  }

  // 4. Update Pill 5 row totals + structural elements (if on custom tab)
  if(activePill === "custom"){
    (STATE.sel.custom.upgrades || []).forEach(function(r, i){
      var cost = r.pricing === "flat" ? pn(r.amount) : pn(r.rate) * pn(r.qty);
      var el = document.getElementById("custup-total-"+i);
      if(el) el.textContent = cost > 0 ? fmt(cost) : "—";
    });
    (STATE.sel.custom.credits || []).forEach(function(r, i){
      var amt = pn(r.amount);
      var el = document.getElementById("custcr-total-"+i);
      if(el) el.textContent = amt > 0 ? "−"+fmt(amt) : "—";
    });
    // Pill 5 structural elements
    var upT = computeCustomUpgradesTotal();
    var crT = getInteriorCreditsTotal();
    var intUp = getInteriorUpgradesTotal();
    var netCr = Math.min(crT, upT);
    var overCap = crT > intUp;
    var netV = upT - netCr;
    var partA = document.getElementById("pill5-partA-badge");
    if(partA) partA.textContent = fmt(upT);
    var partB = document.getElementById("pill5-partB-badge");
    if(partB){
      partB.textContent = crT > 0 ? "−"+fmt(crT) : "$0";
      partB.style.background = crT > 0 ? "var(--amber-dark)" : "";
      partB.style.color = crT > 0 ? "#fff" : "";
    }
    var netBar = document.getElementById("pill5-net-bar");
    if(netBar) netBar.style.background = netV < 0 ? "var(--g800)" : "";
    var netTot = document.getElementById("pill5-net-total");
    if(netTot) netTot.textContent = (netV < 0 ? "−" : "") + fmt(Math.abs(netV));
    var splitLine = document.getElementById("pill5-split-line");
    if(splitLine) splitLine.style.display = crT === 0 ? "none" : "";
    var splitUp = document.getElementById("pill5-split-up");
    if(splitUp) splitUp.textContent = fmt(upT);
    var splitCr = document.getElementById("pill5-split-cr");
    if(splitCr) splitCr.textContent = fmt(netCr);
    var splitCapNote = document.getElementById("pill5-split-capnote");
    if(splitCapNote) splitCapNote.style.display = netCr < crT ? "" : "none";
    var splitRawCr = document.getElementById("pill5-split-rawcr");
    if(splitRawCr) splitRawCr.textContent = fmt(crT);
    var capWarn = document.getElementById("pill5-cap-warning");
    if(capWarn) capWarn.style.display = (overCap && STATE.model && !isCustomFloorPlan()) ? "" : "none";
    var capCreds = document.getElementById("pill5-cap-creds");
    if(capCreds) capCreds.textContent = fmt(crT);
    var capUpg = document.getElementById("pill5-cap-upg");
    if(capUpg) capUpg.textContent = fmt(intUp);
  }

  // 5. Update all 5 pill header badges (totals ripple across pills via custom's net)
  var totals = {
    docusign:   computeSelPillTotal("docusign"),
    electrical: computeSelPillTotal("electrical"),
    plumbing:   computeSelPillTotal("plumbing"),
    trim:       computeSelPillTotal("trim"),
    custom:     computeCustomUpgradesTotal() - getInteriorCreditsTotal()
  };
  Object.keys(totals).forEach(function(k){
    var badge = document.getElementById("selpill-badge-"+k);
    if(badge){
      var t = totals[k];
      badge.textContent = (t < 0 ? "−" : "") + fmt(Math.abs(t));
    }
  });

  // 6. Fall through to the standard running-total refresh (header + data-livesum spans + autosave)
  refreshLiveTotals();
}

function updSelToggle(pillKey, id, checked){
  STATE.sel[pillKey].toggles[id] = !!checked;
  renderCurrentStep();
}
function stepSelQty(path, delta){
  // path = "sel.pillKey.itemId"
  var parts = path.split(".");
  var pill = parts[1], id = parts[2];
  STATE.sel[pill].qtys[id] = Math.max(0, pi(STATE.sel[pill].qtys[id]) + delta);
  renderCurrentStep();
}
function updSelNum(pillKey, id, type, val){
  var bucket = type === "sf" ? "sfs" : "lfs";
  STATE.sel[pillKey][bucket][id] = pn(val);
  refreshStep7Live();
}
function updSelRadio(path, val){
  var parts = path.split(".");
  STATE.sel[parts[1]][parts[2]] = val;
  renderCurrentStep();
}
function addSelCustomLine(pillKey){
  STATE.sel[pillKey].customLines.push({desc:"", amount:0});
  renderCurrentStep();
}
function delSelCustomLine(pillKey, i){
  STATE.sel[pillKey].customLines.splice(i, 1);
  renderCurrentStep();
}
function updSelCustomLine(pillKey, i, field, val){
  var r = STATE.sel[pillKey].customLines[i];
  if(field === "desc") { r.desc = val; refreshStep7Live(); return; }
  r.amount = pn(val);
  refreshStep7Live();
}
function addConcFinishLine(){
  STATE.sel.trim.concreteFinishLines.push({desc:"", rate:0, sqft:0});
  renderCurrentStep();
}
function delConcFinishLine(i){
  STATE.sel.trim.concreteFinishLines.splice(i, 1);
  renderCurrentStep();
}
function updConcFinishLine(i, field, val){
  var r = STATE.sel.trim.concreteFinishLines[i];
  if(field === "desc") { r.desc = val; refreshStep7Live(); return; }
  r[field] = pn(val);
  refreshStep7Live();
}
function addCustomUpgrade(){
  STATE.sel.custom.upgrades.push({trade:"", subType:"both", pricing:"flat", desc:"", amount:0, rate:0, unit:"SF", qty:0});
  renderCurrentStep();
}
function delCustomUpgrade(i){ STATE.sel.custom.upgrades.splice(i,1); renderCurrentStep(); }
function updCustomUpgrade(i, field, val){
  var r = STATE.sel.custom.upgrades[i];
  if(field === "amount" || field === "rate" || field === "qty") r[field] = pn(val);
  else r[field] = val;
  // Re-render for layout-changing fields (trade shows/hides subType toggle, pricing swaps fields, unit/subType)
  if(field === "pricing" || field === "trade" || field === "unit" || field === "subType") renderCurrentStep();
  else refreshStep7Live();
}
function addCustomCredit(){
  STATE.sel.custom.credits.push({trade:"", subType:"both", desc:"", amount:0});
  renderCurrentStep();
}
function delCustomCredit(i){ STATE.sel.custom.credits.splice(i,1); renderCurrentStep(); }
function updCustomCredit(i, field, val){
  var r = STATE.sel.custom.credits[i];
  if(field === "amount") r.amount = pn(val);
  else r[field] = val;
  if(field === "trade" || field === "subType") renderCurrentStep();
  else refreshStep7Live();
}

/* ═══════════════════════════════════════════════════════════════
   UPGRADE TEXT & BULLET GENERATION — reads STATE, produces arrays
   for Contract wording (Part E) and PDF pricing tables.
   ═══════════════════════════════════════════════════════════════ */

function gatherUpgradeTextLines(){
  // Returns array of human-readable strings for contract wording (no dollar amounts)
  var lines = [];
  if(!STATE.int) return lines;
  var S = STATE;
  var cu = S.cabUpgrades;
  var isCust = isCustomFloorPlan();

  // Step 5 — CAD modifications
  var cadList = computeCadCharges(S);
  cadList.forEach(function(c){
    if(c.cost > 0 || c.cost < 0){
      // Strip pricing info (e.g. "× $330", "× $225") from labels for contract notes
      var cleanLabel = c.label.replace(/\s*×\s*\$[\d,.]+/g, "").trim();
      lines.push(cleanLabel);
    }
  });

  // Step 6 Sub-Tab A — Cabinets
  if(cu){
    // Craftsman door style
    var ds = cu.doorStyle || {};
    ["kitchen","island","laundry","baths","other"].forEach(function(area){
      if(ds[area]) lines.push("Door Style — "+area.charAt(0).toUpperCase()+area.slice(1)+": "+ds[area]);
    });
    (cu.customCraftRows||[]).forEach(function(r){
      if(r.area && r.finish) lines.push("Custom Craftsman: "+r.area+" — "+r.finish);
    });
    // Kitchen upgrades
    var kNames = {doorsToDrawers:"Doors to Drawers", fridgePanel:"Fridge Panel", hoodVent:"Hood Vent", tallPantry:"Tall Pantry", lazySusan:"Lazy Susan"};
    if(cu.kitchen) Object.keys(kNames).forEach(function(k){
      var qty = pi(cu.kitchen[k]);
      if(qty > 0) lines.push("Kitchen: "+kNames[k]+" (×"+qty+")");
    });
    // Inserts
    if(cu.inserts){
      ["pullOut","drawerRoll","custom"].forEach(function(k){
        var ins = cu.inserts[k];
        if(ins && pi(ins.qty) > 0){
          var iLabel = {pullOut:"Trash Can / Spice Pull Out Insert", drawerRoll:"Drawer / Roll Out / Tip Out Insert", custom:"Custom Cabinet Insert"}[k];
          var displayLabel = ins.note ? ins.note + " Insert" : iLabel;
          lines.push("Cabinet Insert: "+displayLabel+" (×"+pi(ins.qty)+")");
        }
      });
    }
    // Laundry
    if(cu.laundry){
      if(pi(cu.laundry.uppersWD)>0) lines.push("Laundry: Uppers Above W/D (×"+pi(cu.laundry.uppersWD)+")");
      if(pi(cu.laundry.tallCab)>0) lines.push("Laundry: Tall Cabinet (×"+pi(cu.laundry.tallCab)+")");
    }
    // Bath
    if(cu.bath){
      if(pi(cu.bath.drawerVanity)>0) lines.push("Bath: Drawer Stack Vanity (×"+pi(cu.bath.drawerVanity)+")");
      if(pi(cu.bath.tallLinen)>0) lines.push("Bath: Tall Linen (×"+pi(cu.bath.tallLinen)+")");
      if(pi(cu.bath.makeupSeat)>0) lines.push("Bath: Makeup Seat (×"+pi(cu.bath.makeupSeat)+")");
    }
    // Custom cabinetry rows
    (cu.customRows||[]).forEach(function(r){
      if(r.area && pn(r.lf)>0){
        var type = r.type==="uppersLowers"?"Uppers & Lowers":"Lowers Only";
        lines.push("Custom Cabinetry: "+r.area+" — "+type);
      }
    });
    // Custom line items
    (cu.customLines||[]).forEach(function(r){
      if(r.desc) lines.push("Cabinet Custom: "+r.desc+(r.area?" — "+r.area:""));
    });
    // Discount
    if(pn(cu.discount)>0) lines.push("Cabinet Discount Applied");
  }

  // Step 6 Sub-Tab B — Countertops
  if(S.ct){
    // Tier selections
    var tierData = CT_TIER_DATA[canonicalModel(S.model)] || {};
    var tiers = S.ct.tiers || {};
    CT_AREA_KEYS.forEach(function(ak){
      var sel = tiers[ak];
      if(!sel) return;
      var td = tierData[ak];
      var tierLabel = sel === "t2" ? "Tier 2" : "Tier 3";
      lines.push("Countertop "+tierLabel+": "+(CT_AREA_LABELS[ak]||ak));
    });
    // Custom areas
    (S.ct.areas||[]).forEach(function(a){
      if(a.area && pn(a.sqft)>0) lines.push("Countertop Upgrade: "+a.area);
    });
    if(S.ct.notes) lines.push("Countertop Notes: "+S.ct.notes);
  }

  // Step 7 — Selections (Pills 1-4)
  ["docusign","electrical","plumbing","trim"].forEach(function(pillKey){
    var defs = SEL_DEFS[pillKey];
    if(!defs || !S.sel || !S.sel[pillKey]) return;
    var sel = S.sel[pillKey];
    function processItem(it){
      if(it.type === "toggle" && sel.toggles[it.id]) lines.push(it.label);
      if(it.type === "qty" && pi(sel.qtys[it.id]) > 0){
        var qty = pi(sel.qtys[it.id]);
        lines.push(it.label+" (×"+qty+")");
      }
      if(it.type === "sf" && pn(sel.sfs[it.id]) > 0) lines.push(it.label);
      if(it.type === "lf" && pn(sel.lfs[it.id]) > 0) lines.push(it.label);
    }
    defs.sections.forEach(function(sec){
      if(sec.type === "radio" && sel[sec.id]) lines.push(sec.title+": "+sel[sec.id]);
      // Shower calculator — generate contract note per shower
      if(sec.type === "showerCalc" && sel.showerUpgrade && sel.showers){
        sel.showers.forEach(function(sh){
          lines.push(showerContractNote(sh));
        });
      }
      (sec.items||[]).forEach(processItem);
      (sec.subsections||[]).forEach(function(sub){ sub.items.forEach(processItem); });
    });
  });

  // Step 7 — Concrete finish lines
  (S.sel.trim.concreteFinishLines||[]).forEach(function(r){
    if(r.desc && (pn(r.rate)*pn(r.sqft))>0) lines.push("Concrete Finish: "+r.desc);
  });

  // Step 7 Pill 5 — Custom upgrades
  (S.sel.custom.upgrades||[]).forEach(function(r){
    if(r.pricing === "flat" && pn(r.amount) > 0) lines.push("Custom: "+(r.desc||"Upgrade"));
    else if(pn(r.rate)*pn(r.qty) > 0) lines.push("Custom: "+(r.desc||"Upgrade")+" (×"+pi(r.qty)+")");
  });

  // Step 7 Pill 5 — Credits
  (S.sel.custom.credits||[]).forEach(function(r){
    if(pn(r.amount)>0) lines.push("Credit: "+(r.desc||"Customer-provided item")+" (−"+fmt(pn(r.amount))+")");
  });

  return lines;
}

function gatherUpgradeBulletItems(){
  // Returns array of {label, cost} for PDF pricing tables
  var items = [];
  if(!STATE.int) return items;
  var S = STATE;
  var cu = S.cabUpgrades;

  // CAD charges
  computeCadCharges(S).forEach(function(c){
    if(c.cost !== 0) items.push({label:c.label, cost:c.cost});
  });

  // Cab upgrades (non-plan): use computeCabSections line items
  if(cu){
    var ds = cu.doorStyle || {};
    var m = canonicalModel(S.model);
    var cr = CRAFTSMAN[m] || {paint:{}, stain:{}};
    var areaLabels = {kitchen:"Kitchen", island:"Island", laundry:"Laundry", baths:"Baths", other:"Other"};
    ["kitchen","island","laundry","baths","other"].forEach(function(area){
      var f = ds[area];
      if(!f) return;
      var cost = 0;
      if(f === "paint") cost = pn(cr.paint && cr.paint[area]);
      else if(f === "stain") cost = pn(cr.stain && cr.stain[area]);
      if(cost > 0) items.push({label:"Craftsman "+f.charAt(0).toUpperCase()+f.slice(1)+" — "+(areaLabels[area]||area), cost:cost});
    });
    // Custom craftsman rows
    (cu.customCraftRows || []).forEach(function(r){
      var rate = r.finish === "stain" ? 45 : (r.finish === "paint" ? 35 : 0);
      if(pn(r.lf) > 0 && rate > 0) items.push({label:"Craftsman "+r.finish+" — "+(r.area||"Custom"), cost:rate*pn(r.lf)});
    });
    // Kitchen upgrades — rates MUST match computeCabSections (line 2865)
    if(cu.kitchen){
      var k = cu.kitchen;
      var kItems = [
        {key:"doorsToDrawers", lbl:"Doors to Drawers", cost: pi(k.doorsToDrawers)*250},
        {key:"fridgePanel",    lbl:"Fridge Panel",      cost: pi(k.fridgePanel)*350},
        {key:"hoodVent",       lbl:"Hood Vent",          cost: k.hoodVent ? 2200 : 0},
        {key:"tallPantry",     lbl:"Tall Pantry",        cost: k.tallPantry ? 1200 : 0},
        {key:"lazySusan",      lbl:"Lazy Susan",         cost: k.lazySusan ? 850 : 0}
      ];
      kItems.forEach(function(ki){
        if(ki.cost > 0){
          var qty = pi(k[ki.key]);
          items.push({label:"Kitchen: "+ki.lbl+" ×"+qty, cost:ki.cost});
        }
      });
    }
    // Inserts — rates MUST match computeCabSections (line 2869)
    if(cu.inserts){
      var iItems = [
        {key:"pullOut",    lbl:"Trash Can / Spice Pull Out Insert",   rate:350},
        {key:"drawerRoll", lbl:"Drawer / Roll Out / Tip Out Insert",  rate:275},
        {key:"custom",     lbl:"Custom Cabinet Insert",    rate:500}
      ];
      iItems.forEach(function(ii){
        var ins = cu.inserts[ii.key];
        if(ins && pi(ins.qty)>0){
          var displayLabel = ins.note ? ins.note + " Insert" : ii.lbl;
          items.push({label:"Insert: "+displayLabel+" ×"+pi(ins.qty), cost:pi(ins.qty)*ii.rate});
        }
      });
    }
    // Laundry — rates MUST match computeCabSections (line 2871)
    if(cu.laundry){
      if(cu.laundry.uppersWD) items.push({label:"Laundry: Uppers Above W/D ×"+pi(cu.laundry.uppersWD), cost:pi(cu.laundry.uppersWD)*1250});
      if(cu.laundry.tallCab) items.push({label:"Laundry: Tall Cabinet ×"+pi(cu.laundry.tallCab), cost:pi(cu.laundry.tallCab)*1200});
    }
    // Bath — rates MUST match computeCabSections (line 2874)
    if(cu.bath){
      if(pi(cu.bath.drawerVanity)>0) items.push({label:"Bath: Drawer Stack Vanity ×"+pi(cu.bath.drawerVanity), cost:pi(cu.bath.drawerVanity)*350});
      if(pi(cu.bath.tallLinen)>0) items.push({label:"Bath: Tall Linen ×"+pi(cu.bath.tallLinen), cost:pi(cu.bath.tallLinen)*1250});
      if(pi(cu.bath.makeupSeat)>0) items.push({label:"Bath: Makeup Seat ×"+pi(cu.bath.makeupSeat), cost:pi(cu.bath.makeupSeat)*350});
    }
    // Custom rows
    (cu.customRows||[]).forEach(function(r){
      var rate = r.type==="uppersLowers"?450:(r.type==="lowersOnly"?350:0);
      if(pn(r.lf)>0 && rate>0) items.push({label:"Custom: "+r.area+" ("+r.type.replace("uppersLowers","U&L").replace("lowersOnly","Lowers")+")", cost:rate*pn(r.lf)});
    });
    (cu.customLines||[]).forEach(function(r){
      if(pn(r.amount)>0) items.push({label:"Custom: "+(r.desc||"Line item"), cost:pn(r.amount)});
    });
    // Cabinet discount
    if(pn(cu.discount) > 0) items.push({label:"Cabinet Discount", cost: -pn(cu.discount)});
  }

  // Countertop upgrades — plan charge + tier selections + custom areas
  var ctS = computeCtSections(S);
  if(!isCustomFloorPlan() && ctS.planCharge > 0){
    items.push({label:"Countertop: Plan-Based Charge", cost: ctS.planCharge});
  }
  // Tier selections
  var tierData = CT_TIER_DATA[canonicalModel(S.model)] || {};
  var ctTiers = (S.ct && S.ct.tiers) || {};
  var ctTierSF = (S.ct && S.ct.tierSF) || {};
  CT_AREA_KEYS.forEach(function(ak){
    var sel = ctTiers[ak];
    if(!sel) return;
    var td = tierData[ak]; if(!td) return;
    var baseCost = sel === "t2" ? td.t2 : (sel === "t3" ? td.t3 : 0);
    var userSF = pn(ctTierSF[ak]);
    if(userSF > 0 && td.sf > 0 && Math.abs(userSF - td.sf) > 0.01) baseCost = baseCost * (userSF / td.sf);
    baseCost = Math.round(baseCost * 100) / 100;
    if(baseCost > 0){
      var tierLabel = sel === "t2" ? "Tier 2" : "Tier 3";
      items.push({label:"Countertop "+tierLabel+": "+(CT_AREA_LABELS[ak]||ak), cost: baseCost});
    }
  });
  // Custom areas
  if(S.ct)(S.ct.areas||[]).forEach(function(a){
    if(pn(a.sqft)>0) items.push({label:"Countertop: "+a.area, cost:pn(a.rate)*pn(a.sqft)});
  });

  // Selections pills 1-4
  ["docusign","electrical","plumbing","trim"].forEach(function(pk){
    var defs = SEL_DEFS[pk]; if(!defs || !S.sel[pk]) return;
    var sel = S.sel[pk];
    function proc(it){
      var cost = computeSelItemCost(it, sel);
      if(cost > 0) items.push({label:it.label+(it.type==="qty"?" ×"+pi(sel.qtys[it.id]):""), cost:cost});
    }
    defs.sections.forEach(function(sec){
      // Shower calculator — add each shower as a bullet
      if(sec.type === "showerCalc" && sel.showerUpgrade && sel.showers){
        sel.showers.forEach(function(sh){
          var c = computeShowerCost(sh);
          if(c.total > 0) items.push({label: showerContractNote(sh), cost: Math.round(c.total)});
        });
      }
      (sec.items||[]).forEach(proc);
      (sec.subsections||[]).forEach(function(sub){ sub.items.forEach(proc); });
    });
  });

  // Concrete finish
  (S.sel.trim.concreteFinishLines||[]).forEach(function(r){
    var cost = pn(r.rate)*pn(r.sqft);
    if(cost>0) items.push({label:"Concrete: "+(r.desc||"Finish"), cost:cost});
  });

  // Custom upgrades
  (S.sel.custom.upgrades||[]).forEach(function(r){
    var cost = r.pricing==="flat"?pn(r.amount):pn(r.rate)*pn(r.qty);
    if(cost>0) items.push({label:"Custom: "+(r.desc||"Upgrade"), cost:cost});
  });

  // Credits (negative)
  (S.sel.custom.credits||[]).forEach(function(r){
    if(pn(r.amount)>0) items.push({label:"Credit: "+(r.desc||"Customer-provided"), cost:-pn(r.amount)});
  });

  return items;
}

/* ═══════════════════════════════════════════════════════════════
   STEP 8 — CONTRACT PAGE
   ═══════════════════════════════════════════════════════════════ */
function renderStep8(){
  // Initialize interior state defensively
  if(!STATE.int) initInteriorState();
  else applyIntMetrics();
  initCabUpgradesState();
  initSelState();

  // Budget inputs from Step 1 (sales-rep entered)
  var shellContract  = pn(STATE.shellContract);
  var concreteBudget = pn(STATE.concreteBudget);
  var laborBudget    = pn(STATE.laborBudget);

  // P10 entered on this step (moved from Step 1 per new workflow)
  var p10 = pn(STATE.customer.p10);
  var mft = getMFTMarkup();            // auto-applied on remote branches
  var p10WithMFT = p10 + mft;

  // Interior
  var cabS = computeCabSections();
  var ctS  = computeCtSections();
  var cadCharges = [];
  computeCadCharges().forEach(function(c){ cadCharges.push(c); });
  var cadTotal = 0;
  cadCharges.forEach(function(c){ cadTotal += c.cost; });
  var ctPlanCharge = isCustomFloorPlan() ? 0 : ctS.planCharge;
  var cadBasedKPI = cadTotal + ctPlanCharge + metricAdj;
  var selUpTotal = getSelectionsUpgradesTotal();
  var effCredits = getEffectiveCredits();
  var upgradesKPI = cabS.upgradesSubtotal + ctS.upgradesSubtotal + selUpTotal - effCredits;
  var intContract = computeInteriorContractPrice();

  var turnkeyTotal = shellContract + intContract;
  var livingSF = livSF();
  var shellPerSF = livingSF > 0 ? shellContract / livingSF : 0;
  var intPerSF   = livingSF > 0 ? intContract / livingSF : 0;
  var totalPerSF = shellPerSF + intPerSF;
  var branchLbl  = BRANCHES[STATE.branch] ? BRANCHES[STATE.branch].label : STATE.branch;

  var baseINT = 0;
  var isCustomFP = isCustomFloorPlan();
  if(!isCustomFP) baseINT = getIntContractForBranch(STATE.model);

  // Reconciliation: Shell should == (P10 + MFT + Concrete + Labor)
  var reconcileExpected = p10WithMFT + concreteBudget + laborBudget;
  var reconcileDelta = shellContract - reconcileExpected;

  var h = '';

  // ── Header banner ──
  h += '<div class="banner banner-info"><strong>Contract Breakdown</strong> — '
     +   esc(STATE.model || "(no model selected)")
     +   ' <span class="info-chip">'+esc(branchLbl)+'</span>'
     + '</div>';

  // ── PART A: Shell Contract Summary (live-updates from Step 1 OR inline editor below) ──
  h += '<div class="card">';
  h +=   '<div class="section-hdr section-hdr-red"><span>Part A · Exterior Shell Contract</span></div>';
  h +=   '<div class="kpi-grid">';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">Estimated Shell Contract</div><div class="kpi-val" id="step8-kpi-shell">'+fmt(shellContract)+'</div></div>';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">Concrete Budget</div><div class="kpi-val" id="step8-kpi-conc">'+fmt(concreteBudget)+'</div></div>';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">Labor Budget</div><div class="kpi-val red" id="step8-kpi-labor">'+fmt(laborBudget)+'</div></div>';
  h +=   '</div>';
  h +=   '<div class="card-pad">';
  h +=     '<div style="font-size:12px;color:var(--g600);padding:4px 0 10px">Edit these on Step 1, or use the inline editor below the P10 input to adjust without leaving this page.</div>';
  h +=     '<div class="total-bar"><span class="total-lbl">Total Exterior Shell Package</span><span class="total-val" id="step8-shell-total-bar">'+fmt(shellContract)+'</span></div>';
  h +=   '</div>';
  h += '</div>';

  var metricAdj = computeMetricAdjustment();

  // ── PART B: Interior Turnkey Contract ──
  h += '<div class="card">';
  h +=   '<div class="section-hdr section-hdr-red"><span>Part B · Interior Turnkey Contract</span></div>';
  h +=   '<div class="kpi-grid">';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">Base Turnkey Adder</div><div class="kpi-val">'+(isCustomFP ? '<span style="font-size:13px">Custom Floor Plan</span>' : fmt(baseINT))+'</div></div>';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">CAD-Based Charges</div><div class="kpi-val">'+fmt(cadBasedKPI)+'</div></div>';
  h +=     '<div class="kpi-box"><div class="kpi-lbl">Upgrades Selected</div><div class="kpi-val">'+fmt(upgradesKPI)+'</div></div>';
  h +=   '</div>';
  h +=   '<div class="card-pad">';
  if(livingSF > 0){
    h += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px">';
    h +=   '<div class="kpi-box"><div class="kpi-lbl">Shell $/SF</div><div class="kpi-val" id="step8-shellPerSF" style="font-size:15px">'+fmtC(shellPerSF)+'/SF</div></div>';
    h +=   '<div class="kpi-box"><div class="kpi-lbl">Interior $/SF</div><div class="kpi-val" style="font-size:15px">'+fmtC(intPerSF)+'/SF</div></div>';
    h +=   '<div class="kpi-box"><div class="kpi-lbl">Total $/SF</div><div class="kpi-val" id="step8-totalPerSF" style="font-size:18px;font-weight:700">'+fmtC(totalPerSF)+'/SF</div></div>';
    h += '</div>';
  }
  h +=     '<div style="margin-top:12px"><div class="total-bar" style="font-size:16px"><span class="total-lbl">Total Contracted Amount</span><span class="total-val" id="step8-turnkey-total">'+fmt(turnkeyTotal)+'</span></div>';
  h +=       '<div style="margin-top:6px;font-size:12px;color:var(--g600)" id="step8-shell-int-split">Shell: '+fmt(shellContract)+' · Interior: '+fmt(intContract)+'</div>';
  h +=     '</div>';
  h +=   '</div>';
  h += '</div>';

  // ── PART C: Cabinet Contract Summary ──
  var baseCabLF = getCabinetryLF(STATE.model, isCustomFP);
  var baseCabContract = baseCabLF * 330;
  var cabUpgTotal = isCustomFP ? cabS.upgradesSubtotal : cabS.cabSummaryTotal;
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Part C · Cabinet Contract Summary</span></div>';
  h +=   '<div class="card-pad">';
  h +=     '<div class="field-row" style="gap:8px">';
  h +=       '<div class="kpi-box" style="flex:1"><div class="kpi-lbl">Base Cabinet Contract</div><div class="kpi-val">'+fmt(baseCabContract)+'</div><div style="font-size:10px;color:var(--g500);margin-top:2px">'+baseCabLF+' LF × $330</div></div>';
  h +=       '<div class="kpi-box" style="flex:1"><div class="kpi-lbl">Total Cabinet Upgrades</div><div class="kpi-val">'+fmt(cabUpgTotal)+'</div></div>';
  h +=       '<div class="kpi-box" style="flex:1"><div class="kpi-lbl" style="font-weight:700">Total Cabinet Contract</div><div class="kpi-val" style="font-weight:700;font-size:18px">'+fmt(baseCabContract + cabUpgTotal)+'</div></div>';
  h +=     '</div>';
  h +=   '</div>';
  h += '</div>';

  // ── PART D: Upgrade Categories Breakdown ──
  var docT = computeSelPillTotal("docusign");
  var elecT = computeSelPillTotal("electrical");
  var plmT  = computeSelPillTotal("plumbing");
  var trmT  = computeSelPillTotal("trim");
  var custUpT = computeCustomUpgradesTotal();
  var crTotal = getInteriorCreditsTotal();
  var catLines = [
    {lbl:"Cabinet Upgrades", val: cabUpgTotal},
    {lbl:"Countertop Upgrades", val: ctPlanCharge + ctS.upgradesSubtotal},
    {lbl:"Docusign INT Upgrades", val: docT},
    {lbl:"Electrical Upgrades", val: elecT},
    {lbl:"Plumbing Upgrades", val: plmT},
    {lbl:"Interior Trim & Flooring", val: trmT},
    {lbl:"Custom Upgrades", val: custUpT}
  ];
  if(crTotal > 0) catLines.push({lbl:"Credits", val: -effCredits, credit:true});
  var grandUpg = 0;
  catLines.forEach(function(c){ grandUpg += c.val; });

  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Part D · Upgrade Categories Breakdown</span></div>';
  h +=   '<table class="ps-table">';
  h +=     '<thead><tr><th>Category</th><th style="text-align:right">Amount</th></tr></thead>';
  h +=     '<tbody>';
  catLines.forEach(function(c){
    var style = c.credit ? ' style="color:var(--green-dark)"' : (c.val === 0 ? ' class="muted"' : '');
    h += '<tr'+style+'><td>'+esc(c.lbl)+'</td><td class="cost">'+(c.credit ? '−'+fmt(Math.abs(c.val)) : fmt(c.val))+'</td></tr>';
  });
  h +=     '<tr class="ps-total"><td>GRAND TOTAL IN UPGRADES</td><td class="cost">'+fmt(grandUpg)+'</td></tr>';
  h +=     '</tbody>';
  h +=   '</table>';
  h += '</div>';

  // ── PART E: Contract Upgrade Wording ──
  var textLines = gatherUpgradeTextLines();
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Part E · Contract Upgrade Selections</span></div>';
  h +=   '<div class="card-pad">';
  if(textLines.length === 0){
    h += '<div class="banner banner-empty">No upgrades selected</div>';
  } else {
    h += '<div style="background:var(--g50);border:1px solid var(--g200);border-radius:var(--radius-sm);padding:12px 16px;font-size:13px;line-height:1.7;max-height:340px;overflow-y:auto">';
    textLines.forEach(function(line){ h += '<div>• '+esc(line)+'</div>'; });
    h += '</div>';
  }
  h +=   '</div>';
  h += '</div>';

  // ── P10 MATERIAL ENTRY — new field on Contract page ──
  h += '<div class="card" style="border-top:3px solid var(--red)">';
  h +=   '<div class="section-hdr"><span>P10 Material Total · Draw Schedule Input</span><span class="badge">Enter Before Draw Schedule</span></div>';
  h +=   '<div class="banner banner-info">Once the P10 material quote is returned from Summertown Metals, enter the total here. Draws 1–3 are computed from this number.'+(isRemoteBranch()?' Material Freight/Transit markup of '+(MFT_PCT[canonicalModel(STATE.model)]?Math.round(MFT_PCT[canonicalModel(STATE.model)]*100):0)+'% will be auto-applied to Draw 1 for '+esc(branchLbl)+'.':'')+'</div>';
  h +=   '<div class="card-pad">';
  h +=     '<div class="field" style="max-width:320px"><label class="field-lbl">P10 Material Total (from Summertown Metals)</label><input class="inp mono num" type="text" id="p10Inp" inputmode="decimal" placeholder="$0" value="'+(p10>0?fmtC(p10):"")+'" oninput="onP10InputContract(this.value)" onblur="onP10ContractBlur(this)"></div>';
  // Containers updated in-place by onP10InputContract so typing never triggers
  // a full re-render (which would drop input focus).
  h +=     '<div id="step8-mft-note">'+buildStep8MFTNoteHTML()+'</div>';
  h +=     '<div id="step8-reconcile">'+buildStep8ReconcileHTML()+'</div>';
  h +=   '</div>';
  h += '</div>';

  // ── INLINE BUDGET EDITOR — adjust Step 1 values without leaving the Contract page.
  //    Edits the same STATE fields as Step 1, so navigating back shows the synced values.
  //    Live-updates Part A KPIs, reconciliation banner, draw schedule, and running total
  //    on every keystroke without dropping focus.
  h += '<div class="card" style="border-top:1px dashed var(--g300)">';
  h +=   '<div class="section-hdr"><span>Adjust Shell Budget</span><span class="badge" style="background:var(--g500);color:#fff">Optional</span></div>';
  h +=   '<div class="banner banner-info" style="font-size:12px">Use these inputs to fine-tune the Shell Contract / Concrete Budget / Labor Budget without going back to Step 1. Useful when the P10 quote returns and you need the reconciliation banner above to land green. Changes here update Step 1 automatically — the two pages always show the same numbers.</div>';
  h +=   '<div class="card-pad">';
  h +=     '<div class="customer-grid">';
  h +=       '<div class="field"><label class="field-lbl">Estimated Total Shell Contract</label><input class="inp mono num" type="text" id="step8-shellInp" inputmode="decimal" placeholder="$0" value="'+(shellContract>0?fmtC(shellContract):"")+'" oninput="onStep8ShellInput(this.value)" onblur="onStep8ShellBlur(this)"></div>';
  h +=       '<div class="field"><label class="field-lbl">Concrete Budget (Draw 2)</label><input class="inp mono num" type="text" id="step8-concInp" inputmode="decimal" placeholder="$0" value="'+(concreteBudget>0?fmtC(concreteBudget):"")+'" oninput="onStep8ConcreteInput(this.value)" onblur="onStep8ConcreteBlur(this)"></div>';
  h +=       '<div class="field"><label class="field-lbl">Labor Budget (Draw 3)</label><input class="inp mono num" type="text" id="step8-laborInp" inputmode="decimal" placeholder="$0" value="'+(laborBudget>0?fmtC(laborBudget):"")+'" oninput="onStep8LaborInput(this.value)" onblur="onStep8LaborBlur(this)"></div>';
  h +=     '</div>';
  h +=   '</div>';
  h += '</div>';

  // ── CONTRACT OPTIONS card (Sprint 1) ──
  // Captures the structured per-contract options that don't fit on Step 1:
  //   - Supersedes previous contract (Patterson revision case)
  //   - Permit allowance override (default $2,000)
  //   - Site Prep Coordination Allowance (Ayer's $70,279)
  //   - Detached Shop material + concrete/labor (Ayer's $14k + $32k)
  // Each value flows to the contract PDF (and the draw schedule for the shop fields).
  var meta = STATE.contractMeta || {};
  var supersedesChk = meta.supersedes ? "checked" : "";
  var supRsnDisabled = meta.supersedes ? "" : "disabled";
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Contract Options</span><span class="badge" style="background:var(--g500);color:#fff">Optional</span></div>';
  h +=   '<div class="card-pad">';

  // Supersedes
  h +=     '<div style="margin-bottom:14px">';
  h +=       '<label class="chk" style="font-weight:600"><input type="checkbox" id="metaSupersedes" '+supersedesChk+' onchange="onSupersedesToggle(this.checked)">Supersedes Previously Signed Contract</label>';
  h +=       '<div style="font-size:11px;color:var(--g500);margin:4px 0 0 28px">Check when issuing a revised contract that replaces an earlier one (interior selections changed enough to require a new draw schedule). Adds a bold banner at the top of the contract PDF.</div>';
  h +=       '<div style="margin:8px 0 0 28px"><div class="field" style="max-width:520px"><label class="field-lbl" style="font-size:11px">Reason for Revision</label><input class="inp" type="text" id="metaSupersedesReason" '+supRsnDisabled+' placeholder="e.g. Customer added tile wet room and tankless WH" value="'+esc(meta.supersedesReason||"")+'" oninput="onContractMetaField(\'supersedesReason\',this.value)"></div></div>';
  h +=     '</div>';

  // Allowance overrides
  h +=     '<div style="font-size:11px;font-weight:600;color:var(--g600);text-transform:uppercase;letter-spacing:.5px;margin:14px 0 6px">Allowance Overrides</div>';
  h +=     '<div class="customer-grid">';
  h +=       '<div class="field"><label class="field-lbl">Permit Allowance</label><input class="inp mono num" type="text" id="metaPermit" inputmode="decimal" placeholder="$2,000" value="'+(pn(meta.permitAllowance)>0?fmtC(meta.permitAllowance):"")+'" oninput="onContractMetaMoneyInput(\'permitAllowance\',this.value)" onblur="onContractMetaMoneyBlur(\'permitAllowance\',this)"></div>';
  h +=       '<div class="field"><label class="field-lbl">Contract Allowance Expense</label><input class="inp mono num" type="text" id="metaSitePrep" inputmode="decimal" placeholder="$0" value="'+(pn(meta.sitePrepAllowance)>0?fmtC(meta.sitePrepAllowance):"")+'" oninput="onContractMetaMoneyInput(\'sitePrepAllowance\',this.value)" onblur="onContractMetaMoneyBlur(\'sitePrepAllowance\',this)"></div>';
  h +=     '</div>';
  h +=     '<div style="font-size:11px;color:var(--g500);margin-top:4px">Permit defaults to $2,000 (template language). Contract Allowance Expense covers coordination costs (excavation, utilities, vendor-quoted items included in the contract price). <strong>Both flow directly to the PM Budget export as PO lines with their own cost codes.</strong></div>';

  // Detached shop / garage
  h +=     '<div style="font-size:11px;font-weight:600;color:var(--g600);text-transform:uppercase;letter-spacing:.5px;margin:18px 0 6px">Detached Shop / Garage <span style="font-weight:400;color:var(--g500);text-transform:none;letter-spacing:0">(if applicable)</span></div>';
  h +=     '<div class="customer-grid">';
  h +=       '<div class="field"><label class="field-lbl">Shop Material (Draw 1 add-on)</label><input class="inp mono num" type="text" id="metaShopMat" inputmode="decimal" placeholder="$0" value="'+(pn(meta.detShopMaterial)>0?fmtC(meta.detShopMaterial):"")+'" oninput="onContractMetaMoneyInput(\'detShopMaterial\',this.value)" onblur="onContractMetaMoneyBlur(\'detShopMaterial\',this)"></div>';
  h +=       '<div class="field"><label class="field-lbl">Shop Concrete + Labor (Draw 2 add-on)</label><input class="inp mono num" type="text" id="metaShopCL" inputmode="decimal" placeholder="$0" value="'+(pn(meta.detShopConcLabor)>0?fmtC(meta.detShopConcLabor):"")+'" oninput="onContractMetaMoneyInput(\'detShopConcLabor\',this.value)" onblur="onContractMetaMoneyBlur(\'detShopConcLabor\',this)"></div>';
  h +=     '</div>';
  h +=     '<div style="font-size:11px;color:var(--g500);margin-top:4px">When > $0, populates the "1st/2nd Draw Shop/Detached Garage Portion" lines on the contract draw schedule. Leave at $0 for no detached structure.</div>';

  h +=   '</div>';
  h += '</div>';

  // ── CONTRACT NOTES card (Sprint 1) ──
  // Free-text textarea that lands verbatim on the contract PDF's
  // "Project Plans and Specification Notes" section. This is the single
  // most-used surface in real contracts — every sample had 30-60 lines
  // of unstructured spec notes (warranty exclusions, customer-supplied
  // items, vendor allowance breakdowns, etc.) that don't fit a structured
  // field. Reps will paste their notes here from the existing Word template.
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Contract Notes</span><span class="badge">Appears on Contract PDF</span></div>';
  h +=   '<div class="card-pad">';
  h +=     '<div style="font-size:12px;color:var(--g600);margin-bottom:8px">Anything that needs to land on the <strong>Project Plans and Specification Notes</strong> section of the contract — interior upgrade descriptions, customer-supplied items, warranty exclusions, site prep vendor breakdowns, special framing/foundation details. Pre-fill anything you would type into the Word template today; this is the bridge until structured fields cover everything.</div>';
  h +=     '<textarea id="metaNotes" class="inp" rows="10" style="font-family:DM Mono,monospace;font-size:12px;line-height:1.5;width:100%;resize:vertical" placeholder="e.g.&#10;FRAMING SPECS: All studs 2x6 EXT and 2x4 INT, spaced 16&quot; OC&#10;ROCK WAINSCOT - 300 SF / 360 SF&#10;NO SPRAY FOAM, customer wants batts in walls and blow-N ceiling&#10;CUSTOMER DOING OWN HARDWOOD FLOORING (no warranty)&#10;Install pocket door — NO WARRANTY&#10;Hood vent to be vented to exterior&#10;180 CT Wood Burning Fireplace — Heatilator EL36" oninput="onContractMetaField(\'notes\',this.value)">'+esc(meta.notes||"")+'</textarea>';
  h +=     '<div style="font-size:11px;color:var(--g500);margin-top:6px">Tip: paragraphs and line breaks are preserved on the PDF. Don\'t type the upgrade list here — it gets auto-appended below from your Step 5/6/7 selections (see Interior Contract Preview).</div>';
  h +=   '</div>';
  h += '</div>';

  // ── INTERIOR CONTRACT PREVIEW (Sprint 2 request #4) ──
  // Shows what the rep's freeform Notes + auto-generated upgrade list will look
  // like when concatenated on the contract PDF. Read-only — render-time
  // concatenation (Option A) means the upgrade list always reflects current
  // Step 5/6/7 state, never gets stale, never overwritten by accident. The
  // rep edits upgrades on Step 6/7; this preview updates automatically.
  var upgradeLines = (typeof gatherUpgradeTextLines === "function") ? gatherUpgradeTextLines() : [];
  var notesPreview = (meta.notes || "").trim();
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Interior Contract — Combined Preview</span><span class="badge" style="background:var(--g500);color:#fff">Read-Only · Auto-Updated</span></div>';
  h +=   '<div class="card-pad">';
  h +=     '<div style="font-size:12px;color:var(--g600);margin-bottom:8px">This is exactly what will land on the contract PDF\'s <strong>Project Plans and Specification Notes</strong> section. Your typed notes appear first, then a paragraph break, then your selected upgrades from Steps 5–7. The upgrade list refreshes automatically when you change selections — you never type it here.</div>';
  h +=     '<div style="background:#FAFAFA;border:1px solid var(--g200);border-radius:4px;padding:14px 18px;font-family:DM Mono,monospace;font-size:11px;line-height:1.6;white-space:pre-wrap;word-wrap:break-word;max-height:400px;overflow-y:auto">';
  if(notesPreview){
    h += esc(notesPreview);
  } else {
    h += '<span style="color:var(--g400);font-style:italic">[No Contract Notes entered yet — type above]</span>';
  }
  if(upgradeLines.length > 0){
    h += '\n\nINTERIOR UPGRADES:\n\n';
    upgradeLines.forEach(function(line){ h += esc(line) + '\n'; });
  } else {
    h += '\n\n<span style="color:var(--g400);font-style:italic">[No upgrades selected on Steps 5–7 yet]</span>';
  }
  h +=     '</div>';
  if(upgradeLines.length > 0){
    h +=   '<div style="font-size:11px;color:var(--g500);margin-top:6px">Upgrade list auto-generated from '+upgradeLines.length+' Step 5–7 selection'+(upgradeLines.length===1?'':'s')+'. To change, go back to those steps.</div>';
  }
  h +=   '</div>';
  h += '</div>';

  // ── DRAW SCHEDULE ──
  // Wrapped in a stable container so the P10 input can update it live without
  // re-rendering the entire Contract page.
  h += '<div id="step8-drawschedule">'+renderDrawScheduleHTML(false, p10WithMFT, concreteBudget, laborBudget, shellContract, turnkeyTotal)+'</div>';

  // ── Contract PDF action buttons (Sprint 2.5: overlay generator is now primary) ──
  // Primary action: full canonical bank contract via pdf-lib coordinate
  // overlay onto the cleaned 14-page template (deterministic, pixel-exact).
  // Secondary action: Send for DocuSign (placeholder until Aaron's backend ships).
  // Tools row: legacy HTML-print path kept callable for diff/comparison while
  // the overlay generator goes through final review; calibration PDF for
  // ongoing coordinate-map tuning.
  h += '<div class="card" style="border-top:3px solid #16a34a">';
  h +=   '<div class="section-hdr"><span>Contract PDFs &amp; Signature</span><span class="badge">Step 8 Final Action</span></div>';
  h +=   '<div class="card-pad" style="display:flex;gap:10px;flex-wrap:wrap">';
  h +=     '<button class="nav-btn nav-next" style="flex:2;min-width:280px;background:#A31A1A;color:#fff;font-weight:700" onclick="generateBankContractFromState()">📋 Save Contract as PDF</button>';
  h +=     '<button class="nav-btn" style="flex:2;min-width:280px;background:#0EA5E9;color:#fff;font-weight:700" onclick="sendForDocuSign()">✍️ Send Contract for DocuSign</button>';
  h +=   '</div>';
  h +=   '<div style="padding:0 16px 14px;font-size:11px;color:var(--g600);line-height:1.5">';
  h +=     '<strong style="color:#A31A1A">Save Contract as PDF</strong> — overlays customer/job data onto the cleaned 14-page bank-contract template using exact PDF coordinates. Output is byte-deterministic and pixel-matches the template every time.<br>';
  h +=     '<strong style="color:#0EA5E9">Send Contract for DocuSign</strong> — '+(BACKEND.config.isEnabled() ? 'sends the contract to buyer'+(STATE.customer.coBuyerName?' + co-buyer':'')+' via DocuSign API.' : 'backend not connected — will guide you through manual DocuSign upload.');
  h +=   '</div>';

  // ── DocuSign Status (if envelope exists) ──
  if(STATE.docusign && STATE.docusign.envelopeId){
    h +=   '<div style="padding:8px 16px 14px;border-top:1px solid var(--g200);margin-top:4px">';
    h +=     '<div style="font-size:10px;font-weight:600;text-transform:uppercase;color:var(--g500);letter-spacing:.5px;margin-bottom:6px">DocuSign Status</div>';
    h +=     '<div style="font-size:12px;color:var(--g700);line-height:1.6">';
    h +=       '<strong>Envelope:</strong> <code style="font-family:var(--font-mono);font-size:11px">'+esc(STATE.docusign.envelopeId)+'</code><br>';
    if(STATE.docusign.sentAt) h += '<strong>Sent:</strong> '+new Date(STATE.docusign.sentAt).toLocaleString()+'<br>';
    if(STATE.docusign.signedAt) h += '<strong>Signed:</strong> '+new Date(STATE.docusign.signedAt).toLocaleString()+'<br>';
    if(STATE.docusign.signers && STATE.docusign.signers.length > 0){
      h += '<strong>Signers:</strong><br>';
      STATE.docusign.signers.forEach(function(s){
        var statusIcon = s.status === "signed" ? "✅" : (s.status === "sent" || s.status === "delivered" ? "📧" : (s.status === "declined" ? "❌" : "⏳"));
        h += '  '+statusIcon+' '+esc(s.name)+' ('+esc(s.role)+') — '+esc(s.status)+'<br>';
      });
    }
    h +=     '</div>';
    h +=   '</div>';
  }

  // ── Data Exports ──
  h +=   '<div style="padding:8px 16px 14px;border-top:1px solid var(--g200);margin-top:4px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">';
  h +=     '<span style="font-size:10px;color:var(--g500);font-weight:600;text-transform:uppercase;letter-spacing:0.05em;margin-right:4px">Exports:</span>';
  h +=     '<button class="nav-btn" style="font-size:11px;padding:6px 10px;background:#F59E0B;color:#fff;border-color:#F59E0B;font-weight:600" onclick="exportPMBudgetXLSX()">📦 PM Budget (.xlsx)</button>';
  h +=     '<button class="nav-btn" style="font-size:11px;padding:6px 10px" onclick="exportQBLineItemsCSV()">📥 QB Line Items (.csv)</button>';
  h +=   '</div>';
  h +=   '<div style="padding:8px 16px 14px;border-top:1px solid var(--g200);margin-top:4px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">';
  h +=     '<span style="font-size:10px;color:var(--g500);font-weight:600;text-transform:uppercase;letter-spacing:0.05em;margin-right:4px">Tools:</span>';
  h +=     '<button class="nav-btn" style="font-size:11px;padding:6px 10px" onclick="generateBankContractCalibration()">🎯 Calibration PDF</button>';
  h +=   '</div>';
  h += '</div>';

  // ── Other / Legacy PDFs (kept for draft review) ──
  h += '<div class="card">';
  h +=   '<div class="section-hdr"><span>Other PDFs (Draft / Reference)</span></div>';
  h +=   '<div class="card-pad" style="display:flex;gap:10px;flex-wrap:wrap">';
  h +=     '<button class="nav-btn" style="flex:1;min-width:220px" onclick="printUpgradesPDF()">📄 Customer Upgrades PDF</button>';
  h +=     '<button class="nav-btn" style="flex:1;min-width:220px" onclick="printDrawSchedulePDF()">📄 Draw Schedule Only</button>';
  h +=     '<button class="nav-btn" style="flex:1;min-width:220px" onclick="printContractsPDF()">📄 Legacy Contracts Summary</button>';
  h +=   '</div>';
  h +=   '<div style="padding:0 16px 14px;font-size:11px;color:var(--g500);line-height:1.5">These older outputs are kept for reference and draft review. The canonical contract for sending to the bank or DocuSign is "Save Contract as PDF" above.</div>';
  h += '</div>';

  // ═══════════════════════════════════════════════════════════════
  // SUBMIT CONTRACT PACKAGE — Final action. Bundles everything
  // for this customer/order and sends to the backend database.
  // ═══════════════════════════════════════════════════════════════
  var checklist = buildSubmissionChecklist();
  var allPassed = checklist.every(function(c){ return c.ok; });
  var subStatus = STATE.submission && STATE.submission.status || "not_submitted";
  var orderLabel = STATE.customer.order ? "#"+STATE.customer.order : "(no order #)";

  h += '<div class="card" style="border-top:4px solid var(--red)">';
  h +=   '<div class="section-hdr" style="background:var(--red)"><span>Submit Contract For Audit</span><span class="badge">'+esc(orderLabel)+'</span></div>';
  h +=   '<div class="card-pad">';

  // Pre-flight checklist
  h +=     '<div style="font-size:11px;font-weight:600;color:var(--g600);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">Pre-Flight Checklist</div>';
  checklist.forEach(function(c){
    var icon = c.ok ? '✅' : '⬜';
    var style = c.ok ? 'color:var(--green-dark)' : 'color:var(--g600)';
    h +=   '<div style="padding:5px 0;font-size:13px;'+style+'">'+icon+' '+esc(c.label);
    if(c.detail) h += ' <span style="font-size:11px;color:var(--g500);margin-left:6px">'+esc(c.detail)+'</span>';
    h +=   '</div>';
  });

  // What gets submitted
  h +=     '<div style="margin-top:16px;padding:12px 14px;background:var(--g50);border:1px solid var(--g200);border-radius:var(--radius-sm);font-size:12px;color:var(--g700);line-height:1.6">';
  h +=       '<strong>When you submit, this package is created under Order '+esc(orderLabel)+':</strong><br>';
  h +=       '• <strong>Contract PDF</strong> — 14-page bank contract with customer data overlaid<br>';
  h +=       '• <strong>DocuSign Envelope</strong> — routed to buyer'+(STATE.customer.coBuyerName ? ' + co-buyer' : '')+' + contracts rep for signature<br>';
  h +=       '• <strong>PM Budget</strong> — full budget breakdown (25 PO lines with cost codes + draw schedule)<br>';
  h +=       '• <strong>QB Line Items</strong> — trade-level line items mapped to QuickBooks accounts<br>';
  h +=       '• <strong>Customer Upgrades</strong> — selection details for each pill<br>';
  h +=       '• <strong>Draw Schedule</strong> — 6-draw payment schedule matching the contract<br>';
  h +=       '• <strong>Complete STATE snapshot</strong> — every field, selection, and calculation preserved<br>';
  h +=       '<br>All documents are stored together and retrievable by order number. The backend assigns a package ID for tracking.';
  h +=     '</div>';

  // Submit button
  h +=     '<div style="margin-top:16px;display:flex;gap:12px;align-items:center;flex-wrap:wrap">';
  if(subStatus === "submitted"){
    h +=     '<button class="nav-btn" style="flex:2;min-width:280px;background:var(--red);color:#fff;font-weight:700;font-size:15px;padding:14px 24px;opacity:.7" onclick="saveContract()">📦 Re-Submit Package</button>';
    h +=     '<div style="font-size:12px;color:var(--green-dark)">✅ Submitted '+(STATE.submission.submittedAt ? new Date(STATE.submission.submittedAt).toLocaleString() : "")+'</div>';
  } else if(subStatus === "submitting"){
    h +=     '<button class="nav-btn" style="flex:2;min-width:280px;background:var(--g400);color:#fff;font-weight:700;font-size:15px;padding:14px 24px" disabled>⏳ Submitting...</button>';
  } else if(subStatus === "error"){
    h +=     '<button class="nav-btn" style="flex:2;min-width:280px;background:var(--red);color:#fff;font-weight:700;font-size:15px;padding:14px 24px" onclick="saveContract()">📦 Retry Submission</button>';
    h +=     '<div style="font-size:12px;color:var(--red)">⚠ '+esc(STATE.submission.error || "Submission failed")+'</div>';
  } else {
    h +=     '<button class="nav-btn" style="flex:2;min-width:280px;background:var(--red);color:#fff;font-weight:700;font-size:15px;padding:14px 24px'+(allPassed?'':';opacity:.6')+'" onclick="saveContract()"'+(allPassed?'':' title="Complete all checklist items first"')+'>📦 Submit Contract For Audit</button>';
    if(!allPassed) h += '<div style="font-size:12px;color:var(--amber-dark)">Complete all checklist items above to submit.</div>';
  }
  h +=     '</div>';

  // Package ID (if submitted)
  if(STATE.submission && STATE.submission.packageId){
    h +=   '<div style="margin-top:12px;padding:8px 12px;background:var(--red-light);border:1px solid #FCA5A5;border-radius:var(--radius-sm);font-size:12px;color:var(--red-dark)">';
    h +=     '<strong>Package ID:</strong> <code style="font-family:var(--font-mono)">'+esc(STATE.submission.packageId)+'</code>';
    if(STATE.submission.submittedBy) h += ' · Submitted by: '+esc(STATE.submission.submittedBy);
    h +=   '</div>';
  }

  h +=   '</div>';
  h += '</div>';

  document.getElementById("stepContainer").innerHTML = h;
}

/* ─── Step 8 reconciliation helpers ─────────────────────────────
   Split into pure HTML builders + a targeted-update handler so the
   P10 input doesn't trigger a full re-render on every keystroke. */
function buildStep8MFTNoteHTML(){
  var p10 = pn(STATE.customer.p10);
  var mft = getMFTMarkup();
  if(p10 <= 0 || mft <= 0) return "";
  var pct = MFT_PCT[canonicalModel(STATE.model)] || 0;
  return '<div style="margin-top:10px;padding:8px 12px;background:var(--amber-light);border:1px solid var(--amber);border-radius:var(--radius-sm);font-size:12px;color:var(--amber-dark)">'
       +   'Remote branch: +'+fmt(mft)+' MFT ('+Math.round(pct*100)+'%) auto-added to Draw 1. Draw 1 basis = '+fmt(p10+mft)
       + '</div>';
}

function buildStep8ReconcileHTML(){
  var shellContract = pn(STATE.shellContract);
  var p10 = pn(STATE.customer.p10);
  var mft = getMFTMarkup();
  var concreteBudget = pn(STATE.concreteBudget);
  var laborBudget = pn(STATE.laborBudget);
  if(shellContract <= 0 || p10 <= 0) return "";
  var reconcileExpected = p10 + mft + concreteBudget + laborBudget;
  var reconcileDelta = shellContract - reconcileExpected;
  var tone = Math.abs(reconcileDelta) < 100 ? 'green' : (reconcileDelta > 0 ? 'amber' : 'red');
  var toneCss = tone === 'green' ? 'background:var(--green-light);border-color:var(--green);color:var(--green-dark)'
               : tone === 'amber' ? 'background:var(--amber-light);border-color:var(--amber);color:var(--amber-dark)'
               : 'background:var(--red-light);border-color:var(--red);color:var(--red-dark)';
  var msg;
  if(tone === 'green'){
    msg = '✓ <strong>Shell reconciles.</strong> P10+MFT + Concrete + Labor = '+fmt(reconcileExpected)+' matches your Shell Contract of '+fmt(shellContract)+'.';
  } else if(reconcileDelta > 0){
    msg = '⚠️ <strong>Under-allocated by '+fmt(reconcileDelta)+'.</strong> Shell Contract ('+fmt(shellContract)+') exceeds P10+MFT + Concrete + Labor ('+fmt(reconcileExpected)+'). Draw 2 and Draw 3 won\'t cover the full shell unless Concrete or Labor budgets are increased on Step 1.';
  } else {
    msg = '⚠️ <strong>Over-allocated by '+fmt(Math.abs(reconcileDelta))+'.</strong> P10+MFT + Concrete + Labor ('+fmt(reconcileExpected)+') exceeds your Shell Contract ('+fmt(shellContract)+'). Increase Shell on Step 1, or reduce Concrete/Labor budgets.';
  }
  return '<div style="margin-top:10px;padding:10px 12px;border:1px solid;border-radius:var(--radius-sm);font-size:12px;line-height:1.5;'+toneCss+'">'+msg+'</div>';
}

/* Contract-page P10 handler — updates state + refreshes only the MFT note,
   reconciliation banner, draw schedule, and running total, without
   destroying the input (which would drop focus during typing). */
/* Shared helper: rebuilds every derived element on the Contract page from
   current STATE. Called by the P10 input and by the inline Shell/Concrete/
   Labor budget inputs so all four edit paths produce identical updates.
   Inputs themselves are never touched (would drop focus mid-typing). */
function refreshStep8Derived(){
  var p10WithMFT     = pn(STATE.customer.p10) + getMFTMarkup();
  var shellContract  = pn(STATE.shellContract);
  var concreteBudget = pn(STATE.concreteBudget);
  var laborBudget    = pn(STATE.laborBudget);
  var intContract    = computeInteriorContractPrice();
  var turnkeyTotal   = shellContract + intContract;
  var livingSF       = livSF();
  var shellPerSF     = livingSF > 0 ? shellContract / livingSF : 0;
  var intPerSF       = livingSF > 0 ? intContract / livingSF : 0;
  var totalPerSF     = shellPerSF + intPerSF;

  // Part A KPIs + total bar
  var kpiShell = document.getElementById("step8-kpi-shell");
  if(kpiShell) kpiShell.textContent = fmt(shellContract);
  var kpiConc = document.getElementById("step8-kpi-conc");
  if(kpiConc) kpiConc.textContent = fmt(concreteBudget);
  var kpiLabor = document.getElementById("step8-kpi-labor");
  if(kpiLabor) kpiLabor.textContent = fmt(laborBudget);
  var shellTotalBar = document.getElementById("step8-shell-total-bar");
  if(shellTotalBar) shellTotalBar.textContent = fmt(shellContract);

  // Part B totals + per-SF
  var tk = document.getElementById("step8-turnkey-total");
  if(tk) tk.textContent = fmt(turnkeyTotal);
  var splitLine = document.getElementById("step8-shell-int-split");
  if(splitLine) splitLine.textContent = "Shell: "+fmt(shellContract)+" · Interior: "+fmt(intContract);
  var perSF = document.getElementById("step8-shellPerSF");
  if(perSF) perSF.textContent = fmtC(shellPerSF)+"/SF";
  var totSF = document.getElementById("step8-totalPerSF");
  if(totSF) totSF.textContent = fmtC(totalPerSF)+"/SF";

  // P10 entry card: MFT note + reconciliation banner
  var mftEl = document.getElementById("step8-mft-note");
  if(mftEl) mftEl.innerHTML = buildStep8MFTNoteHTML();
  var recEl = document.getElementById("step8-reconcile");
  if(recEl) recEl.innerHTML = buildStep8ReconcileHTML();

  // Draw schedule (rebuilt fully — no input focus to preserve inside it)
  var dsEl = document.getElementById("step8-drawschedule");
  if(dsEl){
    dsEl.innerHTML = renderDrawScheduleHTML(false, p10WithMFT,
      concreteBudget, laborBudget, shellContract, turnkeyTotal);
  }

  // Running header total
  renderRunningTotal();
}

function onP10InputContract(v){
  var raw = v.replace(/[^0-9.]/g, "");
  STATE.customer.p10 = pn(raw);
  refreshStep8Derived();
  scheduleSave();
}

function onP10ContractBlur(inp){
  inp.value = STATE.customer.p10 > 0 ? fmtC(STATE.customer.p10) : "";
}

