function buildPsDrawSchedule(){
  // Interior-only tool: everything is turnkey; shell total is user-entered on Step 1.
  var shellTotal  = pn(STATE.shellContract);
  var concBudget  = pn(STATE.concreteBudget);
  var laborBudg   = pn(STATE.laborBudget);
  var p10WithMFT  = pn(STATE.customer.p10) + getMFTMarkup();
  var intContract = computeInteriorContractPrice();

  var d = computeDrawAmounts({
    isShell: false,
    p10WithMFT: p10WithMFT,
    concTotal: concBudget,
    custLabor: laborBudg,
    intContract: intContract,
    shellTotal: shellTotal,
    detP10: 0, detLabor: 0
  });
  var deposit = d.deposit, draw1 = d.draw1, draw2 = d.draw2, draw3 = d.draw3;
  var draw4 = d.draw4, draw5 = d.draw5, draw6 = d.draw6;
  var total = d.total;

  var h = buildPsHeader("Turnkey Contract Draw Schedule");

  var ls = 'style="border-bottom:1px solid #999;padding:8px 0;vertical-align:top"';
  var rs = 'style="border-bottom:1px solid #999;padding:8px 0;text-align:right;font-family:monospace;white-space:nowrap;vertical-align:top"';

  h += '<table style="width:100%;border-collapse:collapse;font-size:12px;margin-top:12px">';
  h +=   '<tr style="border-bottom:2px solid #333"><td style="padding:6px 0"><strong style="font-size:14px">PROJECT COST ITEMIZED</strong></td><td style="text-align:right;padding:6px 0;font-weight:bold;font-size:14px">Amount</td></tr>';

  h += '<tr><td '+ls+'>Contract "Good Faith" Deposit (non-refundable, paid at signing)</td><td '+rs+'>'+fmtMoney(deposit)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>1st Home Draw at Loan Closing</u></strong> (Minimum of 20% of total home contract)<br><span style="font-size:11px;color:#555">Total Shell Material Amount minus Prepayment</span></td><td '+rs+'>'+fmtMoney(draw1)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>2nd Home Draw Upon Concrete Completion</u></strong> (Minimum 20%)<br><span style="font-size:11px;color:#555">Includes remaining material, contract allowance (if applicable), and concrete</span></td><td '+rs+'>'+fmtMoney(draw2)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>3rd Home Draw Upon Framing Completion</u></strong> (Minimum 15%)<br><span style="font-size:11px;color:#555">Includes exterior labor</span></td><td '+rs+'>'+fmtMoney(draw3)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>4th Home Draw</u></strong> (Minimum 20%)<br><span style="font-size:11px;color:#555">20% of total contract upon completion of mechanical rough-in/electric/plumbing/HVAC</span></td><td '+rs+'>'+fmtMoney(draw4)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>5th Home Draw</u></strong> (Minimum 20%)<br><span style="font-size:11px;color:#555">20% of total contract upon completion of drywall/cabinets/countertops</span></td><td '+rs+'>'+fmtMoney(draw5)+'</td></tr>';
  h += '<tr><td '+ls+'><strong><u>6th Home Draw</u></strong> (Minimum 5%)<br><span style="font-size:11px;color:#555">Final Punch/Notice of Completion or Certificate of Occupancy if necessary</span></td><td '+rs+'>'+fmtMoney(draw6)+'</td></tr>';
  h += '<tr style="border-top:2px solid #333;font-weight:700"><td style="padding:8px 0">TOTAL CONTRACTED AMOUNT</td><td style="padding:8px 0;text-align:right;font-family:monospace">'+fmtMoney(total)+'</td></tr>';

  h += '</table>';

  h += '<div style="margin-top:24px;font-size:11px;line-height:1.6">';
  h +=   '<p><strong>Note that progress in construction shall not proceed to the next step until the draw is received on the completed work up to that point.</strong></p>';
  h +=   '<p style="color:#555;margin-top:8px">Contractor accepts cash, checks, and wires. Past due accounts are subject to a monthly fee which will be calculated at the rate of 1.5% monthly interest rate.</p>';
  h += '</div>';
  h += '<div style="margin-top:12px;font-size:9px;color:#999">Summertown Metals Contracting &bull; '+psDateStamp()+'</div>';
  return h;
}

function printToSheet(html, pdfLabel){
  var ps = document.getElementById("printSheet");
  if(!ps){ showToast("Print sheet not ready."); return; }
  ps.innerHTML = html;
  ps.style.display = "block";
  // BUG FIX (A6): richer filename with order # and YYYY-MM-DD so multiple
  // quotes for the same customer don't collide in the downloads folder.
  // Format: "{Customer} - {Order#} - {Label} - {YYYY-MM-DD} - {Version}"
  var savedTitle = document.title;
  var custName = (STATE.customer.name || "").trim();
  var orderNum = (STATE.customer.order || "").trim();
  var d = new Date();
  var dateStr = d.getFullYear() + "-" + String(d.getMonth()+1).padStart(2,"0") + "-" + String(d.getDate()).padStart(2,"0");
  var parts = [];
  if(custName) parts.push(custName);
  if(orderNum) parts.push("#"+orderNum);
  if(pdfLabel) parts.push(pdfLabel);
  parts.push(dateStr);
  parts.push(WIZ_VERSION);
  // Sanitize filename: remove characters that Windows/macOS/Linux reject in filenames
  document.title = parts.join(" - ").replace(/[\\/:*?"<>|]+/g, "_");
  setTimeout(function(){
    try { window.print(); } catch(e){ showToast("Print failed: "+e.message); }
    // Restore title and clean up after the dialog closes
    setTimeout(function(){
      document.title = savedTitle;
      ps.innerHTML = "";
      ps.style.display = "none";
    }, 300);
  }, 150);
}

function requireModel(){
  if(!STATE.model){ showToast("Select a model on Step 1 first."); return false; }
  return true;
}

// Interior-tool gate: soft-warn if Concrete Budget or Labor Budget is $0 on Step 1.
// These feed Draws 2 and 3 directly; zero values print $0.00 on the banking schedule.
function requireConcreteOrConfirm(){
  var conc = pn(STATE.concreteBudget);
  var labor = pn(STATE.laborBudget);
  if(conc > 0 && labor > 0) return true;
  var missing = [];
  if(conc <= 0) missing.push("Concrete Budget (Draw 2)");
  if(labor <= 0) missing.push("Labor Budget (Draw 3)");
  var proceed = window.confirm(
    "Missing on Step 1: " + missing.join(" and ") + ".\n\n" +
    "If you generate a contract now, the corresponding draw will print as $0.00 on the banking draw schedule.\n\n" +
    "• Click OK to generate anyway.\n" +
    "• Click Cancel to return to Step 1 and fill these in first."
  );
  if(!proceed){
    wizGoTo(activeStepIds().indexOf(1));
    showToast("Returned to Step 1 — enter Concrete / Labor Budget to proceed.");
    return false;
  }
  return true;
}

/* ═══ PDF Entrypoints (interior-only) ═══
   Three customer-facing PDFs plus one internal PM budget PDF.
   Removed from parent: Full Contract PDF, Customer Contract (shell-only), Contractor Labor PDF. */
function printUpgradesPDF(){
  if(!requireModel()) return;
  var html = '<div class="ps-page">' + buildPsUpgradesPricing() + '</div>';
  printToSheet(html, "Upgrade Summary");
}
function printContractsPDF(){
  if(!requireModel()) return;
  if(!requireConcreteOrConfirm()) return;
  var html = '';
  // Supersedes banner — prepended to the contract summary page when active.
  // Mirrors the bold "THIS CONTRACT SUPERSEDES THE PREVIOUSLY SIGNED CONTRACT"
  // wording seen on Patterson's revised contract.
  html += buildPsSupersedesBanner();
  html += '<div class="ps-page">' + buildPsContractSummary() + '</div>';
  html += '<div class="ps-page ps-page-break">' + buildPsDrawSchedule() + '</div>';
  // Contract Notes section — free-text from Step 8 textarea, lands as a
  // "Project Plans and Specification Notes" page on the PDF. Only renders
  // when the rep has entered notes; otherwise omitted entirely.
  var notesPage = buildPsContractNotesPage();
  if(notesPage) html += '<div class="ps-page ps-page-break">' + notesPage + '</div>';
  printToSheet(html, "Contracts");
}
function printDrawSchedulePDF(){
  if(!requireModel()) return;
  if(!requireConcreteOrConfirm()) return;
  var html = '';
  html += '<div class="ps-page">' + buildPsDrawSchedule() + '</div>';
  html += '<div class="ps-page ps-page-break">' + buildPsUpgradesPricing() + '</div>';
  html += '<div class="ps-page ps-page-break">' + buildPsUpgradeWording() + '</div>';
  printToSheet(html, "Draw Schedule");
}

/* Legacy stubs — parent tool exported these buttons but the interior-only
   wizard no longer surfaces them. Kept callable so stale references (e.g.
   cached drafts, external bookmarks) don't throw. */
