/* ── Sprint 1: Contract metadata renderers ──────────────────────────
   These render the new Step 8 Contract Options + Contract Notes onto the
   generated PDF. They produce empty strings when their fields are blank /
   off, so PDFs for projects that don't use these features look the same
   as before Sprint 1. */

/* Bold banner shown at the very top of the contract PDF when the rep has
   checked "Supersedes Previously Signed Contract" on Step 8. Wording
   matches the Patterson revised contract verbatim. */
function buildPsSupersedesBanner(){
  var meta = STATE.contractMeta || {};
  if(!meta.supersedes) return "";
  var h = '<div style="margin:0 0 12px 0;padding:14px 18px;background:#FEF3C7;border:2px solid #A31A1A;border-radius:6px;text-align:center">';
  h +=   '<div style="font-size:14px;font-weight:800;color:#A31A1A;letter-spacing:.5px">THIS CONTRACT SUPERSEDES THE PREVIOUSLY SIGNED CONTRACT</div>';
  if(meta.supersedesReason){
    h += '<div style="font-size:11px;color:#555;margin-top:4px;font-style:italic">Reason: '+esc(meta.supersedesReason)+'</div>';
  }
  h += '</div>';
  return h;
}

/* Free-text Contract Notes page — appended to the contracts PDF when the
   rep has typed anything into Step 8's notes textarea. Preserves whitespace
   and line breaks so multi-paragraph notes from the Word template paste in
   cleanly. Returns empty string when no notes are present (no blank page). */
function buildPsContractNotesPage(){
  var meta = STATE.contractMeta || {};
  var notes = (meta.notes || "").trim();
  if(!notes) return "";
  var h = buildPsHeader("Project Plans and Specification Notes");
  h += '<div style="margin-top:14px;padding:14px 18px;background:#FAFAFA;border:1px solid #E5E7EB;border-radius:4px;font-family:var(--font-mono);font-size:11px;line-height:1.6;white-space:pre-wrap;word-wrap:break-word">'+esc(notes)+'</div>';
  // If allowance overrides differ from defaults, show them as a brief
  // structured note at the bottom — useful for the bank reviewer.
  var overrideRows = "";
  if(pn(meta.permitAllowance) !== 2000){
    overrideRows += '<tr><td style="padding:4px 8px;border-bottom:1px solid #ddd">Permit Allowance Override</td><td style="padding:4px 8px;border-bottom:1px solid #ddd;text-align:right;font-family:var(--font-mono)">'+fmt(meta.permitAllowance)+'</td></tr>';
  }
  if(pn(meta.sitePrepAllowance) > 0){
    overrideRows += '<tr><td style="padding:4px 8px;border-bottom:1px solid #ddd">Contract Allowance Expense</td><td style="padding:4px 8px;border-bottom:1px solid #ddd;text-align:right;font-family:var(--font-mono)">'+fmt(meta.sitePrepAllowance)+'</td></tr>';
  }
  if(pn(meta.detShopMaterial) > 0){
    overrideRows += '<tr><td style="padding:4px 8px;border-bottom:1px solid #ddd">Detached Shop Material</td><td style="padding:4px 8px;border-bottom:1px solid #ddd;text-align:right;font-family:var(--font-mono)">'+fmt(meta.detShopMaterial)+'</td></tr>';
  }
  if(pn(meta.detShopConcLabor) > 0){
    overrideRows += '<tr><td style="padding:4px 8px;border-bottom:1px solid #ddd">Detached Shop Concrete + Labor</td><td style="padding:4px 8px;border-bottom:1px solid #ddd;text-align:right;font-family:var(--font-mono)">'+fmt(meta.detShopConcLabor)+'</td></tr>';
  }
  if(meta.foundationType && meta.foundationType !== "slab"){
    var ft = (typeof FOUNDATION_TYPES !== "undefined")
      ? FOUNDATION_TYPES.find(function(f){ return f.key === meta.foundationType; })
      : null;
    overrideRows += '<tr><td style="padding:4px 8px;border-bottom:1px solid #ddd">Foundation Type</td><td style="padding:4px 8px;border-bottom:1px solid #ddd;text-align:right">'+esc(ft ? ft.label : meta.foundationType)+'</td></tr>';
  }
  if(overrideRows){
    h += '<div style="margin-top:18px"><div style="font-size:11px;font-weight:700;color:#A31A1A;margin-bottom:6px">Allowances &amp; Overrides</div>';
    h += '<table style="width:100%;border-collapse:collapse;font-size:11px"><tbody>'+overrideRows+'</tbody></table></div>';
  }
  return h;
}

/* ── Turnkey PDF builders ── */
function buildPsUpgradesPricing(){
  var h = buildPsHeader("Interior Upgrades Pricing Summary");
  var bullets = gatherUpgradeBulletItems();
  h += '<table class="ps-detail-table" style="width:100%;border-collapse:collapse;font-size:12px;margin-top:10px">';
  h +=   '<thead><tr style="border-bottom:2px solid #333"><th style="text-align:left;padding:6px">Item</th><th style="text-align:right;padding:6px">Amount</th></tr></thead>';
  h +=   '<tbody>';
  var total = 0;
  bullets.forEach(function(b){
    total += b.cost;
    var neg = b.cost < 0;
    h += '<tr style="border-bottom:1px solid #ddd"><td style="padding:5px 6px">'+esc(b.label)+'</td><td style="text-align:right;padding:5px 6px;font-family:monospace;'+(neg?"color:green":"")+'">'+( neg ? "−"+fmt(Math.abs(b.cost)) : fmt(b.cost) )+'</td></tr>';
  });
  h +=   '<tr style="border-top:2px solid #333;font-weight:bold"><td style="padding:6px">GRAND TOTAL IN UPGRADES</td><td style="text-align:right;padding:6px;font-family:monospace">'+fmt(total)+'</td></tr>';
  h +=   '</tbody>';
  h += '</table>';
  h += '<div style="margin-top:16px;font-size:10px;color:#777">Summertown Metals Contracting &bull; '+psDateStamp()+' &bull; This estimate is valid for 30 days.</div>';
  return h;
}

function buildPsContractSummary(){
  if(!STATE.int) initInteriorState();
  else applyIntMetrics();
  initCabUpgradesState(); initSelState();

  // Interior-only tool: shell values come from Step 1 (sales-rep entered)
  var shellTotal = pn(STATE.shellContract);
  var concBudget = pn(STATE.concreteBudget);
  var laborBudg  = pn(STATE.laborBudget);
  var p10 = pn(STATE.customer.p10);
  var mft = getMFTMarkup();
  var livSFVal = livSF();
  var shellPerSF = livSFVal > 0 ? shellTotal / livSFVal : 0;
  var branchLbl = BRANCHES[STATE.branch] ? BRANCHES[STATE.branch].label : STATE.branch;

  var kpiBox = 'display:inline-block;text-align:center;padding:8px 12px;border:1px solid #ddd;border-radius:4px;min-width:120px';
  var kpiLbl = 'font-size:10px;color:#777;margin-bottom:2px';
  var kpiVal = 'font-size:16px;font-weight:700';
  var totalBar = 'background:#A31A1A;color:#fff;padding:10px 16px;border-radius:4px;display:flex;justify-content:space-between;align-items:center;margin-top:10px';
  var secHdr = 'background:#A31A1A;color:#fff;padding:6px 12px;font-weight:700;font-size:12px;border-radius:3px;margin:14px 0 8px 0';
  var secHdrDk = 'background:#333;color:#fff;padding:6px 12px;font-weight:700;font-size:12px;border-radius:3px;margin:14px 0 8px 0';

  // ═══ PAGE 1: Parts A + B ═══
  var h = buildPsHeader("Turnkey Contract Summary");

  h += '<div style="background:#F3F4F6;padding:8px 12px;border-radius:4px;font-size:11px;margin-bottom:8px">';
  h +=   '<strong>'+esc(STATE.model||"")+'</strong>';
  h +=   ' &bull; <span style="background:#A31A1A;color:#fff;padding:2px 8px;border-radius:3px;font-size:9px">'+esc(branchLbl)+'</span>';
  if(STATE.customer.name) h += ' &bull; '+esc(STATE.customer.name);
  h += '</div>';

  // Part A — Shell (user-entered lump sum)
  h += '<div style="'+secHdr+'">Part A &middot; Exterior Shell Contract</div>';
  h += '<div style="display:flex;gap:8px;margin-bottom:6px;flex-wrap:wrap">';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Shell Contract (est.)</div><div style="'+kpiVal+'">'+fmt(shellTotal)+'</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Concrete Budget</div><div style="'+kpiVal+'">'+fmt(concBudget)+'</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Labor Budget</div><div style="'+kpiVal+';color:#A31A1A">'+fmt(laborBudg)+'</div></div>';
  h += '</div>';
  h += '<div style="display:flex;gap:8px;margin-bottom:6px;flex-wrap:wrap">';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">P10 Material</div><div style="'+kpiVal+'">'+fmt(p10)+'</div></div>';
  if(mft > 0) h += '<div style="'+kpiBox+';flex:1;border-color:#F59E0B"><div style="'+kpiLbl+'">MFT ('+Math.round((MFT_PCT[canonicalModel(STATE.model)]||0)*100)+'%)</div><div style="'+kpiVal+';color:#B45309">+'+fmt(mft)+'</div></div>';
  h += '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Shell $/SF</div><div style="font-size:14px;font-weight:600">'+(livSFVal>0?fmtC(shellPerSF)+'/SF':'—')+'</div></div>';
  h += '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Branch</div><div style="font-size:12px;font-weight:600">'+esc(branchLbl)+'</div></div>';
  h += '</div>';
  h += '<div style="'+totalBar+'"><span style="font-size:12px">Total Exterior Shell Package</span><span style="font-size:18px;font-weight:700">'+fmt(shellTotal)+'</span></div>';

  // Part B — Interior Turnkey Contract
  var cabS = computeCabSections();
  var ctS  = computeCtSections();
  var cadCharges = []; computeCadCharges().forEach(function(cc){ cadCharges.push(cc); });
  var cadTotal = 0; cadCharges.forEach(function(cc){ cadTotal += cc.cost; });
  var ctPlanCharge = isCustomFloorPlan() ? 0 : ctS.planCharge;
  var cadBasedKPI = cadTotal + ctPlanCharge + computeMetricAdjustment();
  var selUpTotal = getSelectionsUpgradesTotal();
  var effCredits = getEffectiveCredits();
  var upgradesKPI = cabS.upgradesSubtotal + ctS.upgradesSubtotal + selUpTotal - effCredits;
  var intContract = computeInteriorContractPrice();
  var turnkeyTotal = shellTotal + intContract;
  var intPerSF = livSFVal > 0 ? intContract / livSFVal : 0;
  var totalPerSF = shellPerSF + intPerSF;
  var isCustomFP = isCustomFloorPlan();
  var baseINT = isCustomFP ? 0 : getIntContractForBranch(STATE.model);

  h += '<div style="'+secHdr+'">Part B &middot; Interior Turnkey Contract</div>';
  h += '<div style="display:flex;gap:8px;margin-bottom:6px;flex-wrap:wrap">';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Base Turnkey Adder</div><div style="'+kpiVal+'">'+(isCustomFP?'Custom':fmt(baseINT))+'</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">CAD-Based Charges</div><div style="'+kpiVal+'">'+fmt(cadBasedKPI)+'</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Upgrades Selected</div><div style="'+kpiVal+'">'+fmt(upgradesKPI)+'</div></div>';
  h += '</div>';
  if(livSFVal > 0){
    h += '<div style="display:flex;gap:8px;margin-bottom:6px">';
    h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Shell $/SF</div><div style="font-size:13px;font-weight:600">'+fmtC(shellPerSF)+'/SF</div></div>';
    h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Interior $/SF</div><div style="font-size:13px;font-weight:600">'+fmtC(intPerSF)+'/SF</div></div>';
    h +=   '<div style="'+kpiBox+';flex:1;border:2px solid #A31A1A"><div style="'+kpiLbl+'">Total $/SF</div><div style="font-size:15px;font-weight:700">'+fmtC(totalPerSF)+'/SF</div></div>';
    h += '</div>';
  }
  h += '<div style="'+totalBar+'"><span style="font-size:12px">Total Contracted Amount</span><span style="font-size:18px;font-weight:700">'+fmt(turnkeyTotal)+'</span></div>';
  h += '<div style="font-size:10px;color:#555;margin-top:3px">Shell: '+fmt(shellTotal)+' &middot; Interior: '+fmt(intContract)+'</div>';

  // ═══ PAGE 2: Parts C + D ═══
  h += '</div><div class="ps-page ps-page-break">';
  h += buildPsHeader("Turnkey Contract (continued)");

  var baseCabLF = getCabinetryLF(STATE.model, isCustomFP);
  var baseCabContract = baseCabLF * 330;
  var cabUpgTotal = isCustomFP ? cabS.upgradesSubtotal : cabS.cabSummaryTotal;
  h += '<div style="'+secHdrDk+'">Part C &middot; Cabinet Contract Summary</div>';
  h += '<div style="display:flex;gap:8px;margin-bottom:6px">';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Base Contract</div><div style="'+kpiVal+'">'+fmt(baseCabContract)+'</div><div style="font-size:9px;color:#999">'+baseCabLF+' LF × $330</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1"><div style="'+kpiLbl+'">Upgrades</div><div style="'+kpiVal+'">'+fmt(cabUpgTotal)+'</div></div>';
  h +=   '<div style="'+kpiBox+';flex:1;background:#F3F4F6"><div style="'+kpiLbl+';font-weight:700">Total Cabinet Contract</div><div style="'+kpiVal+';font-size:18px">'+fmt(baseCabContract+cabUpgTotal)+'</div></div>';
  h += '</div>';

  var docT=computeSelPillTotal("docusign"), elecT=computeSelPillTotal("electrical"), plmT=computeSelPillTotal("plumbing"), trmT=computeSelPillTotal("trim");
  var custUpT = computeCustomUpgradesTotal();
  var crTotal = getInteriorCreditsTotal();
  var catLines = [
    {lbl:"Cabinet Upgrades",val:cabUpgTotal},{lbl:"Countertop Upgrades",val:ctPlanCharge+ctS.upgradesSubtotal},
    {lbl:"Docusign INT Upgrades",val:docT},{lbl:"Electrical Upgrades",val:elecT},
    {lbl:"Plumbing Upgrades",val:plmT},{lbl:"Interior Trim & Flooring",val:trmT},{lbl:"Custom Upgrades",val:custUpT}
  ];
  if(crTotal > 0) catLines.push({lbl:"Credits",val:-effCredits,credit:true});
  var grandUpg = 0; catLines.forEach(function(cl){ grandUpg += cl.val; });

  h += '<div style="'+secHdrDk+'">Part D &middot; Upgrade Categories Breakdown</div>';
  h += '<table style="width:100%;border-collapse:collapse;font-size:10px">';
  h += '<thead><tr style="border-bottom:2px solid #333"><th style="text-align:left;padding:3px">Category</th><th style="text-align:right;padding:3px">Amount</th></tr></thead><tbody>';
  catLines.forEach(function(cl){
    var sty = cl.credit?'color:#065F46':(cl.val===0?'color:#999':'');
    h += '<tr style="border-bottom:1px solid #ddd;'+sty+'"><td style="padding:3px">'+esc(cl.lbl)+'</td><td style="text-align:right;padding:3px;font-family:monospace">'+(cl.credit?'−'+fmt(Math.abs(cl.val)):fmt(cl.val))+'</td></tr>';
  });
  h += '<tr style="border-top:2px solid #333;font-weight:700"><td style="padding:4px 3px">GRAND TOTAL IN UPGRADES</td><td style="text-align:right;padding:4px 3px;font-family:monospace">'+fmt(grandUpg)+'</td></tr></tbody></table>';
  h += '<div style="margin-top:10px;font-size:9px;color:#999">Summertown Metals Contracting &bull; '+psDateStamp()+'</div>';

  // ═══ PAGE 3: Part E — Upgrade Details (only if upgrades exist) ═══
  var textLines = gatherUpgradeTextLines();
  var bullets = gatherUpgradeBulletItems();
  if(textLines.length > 0 || bullets.length > 0){
    h += '</div><div class="ps-page ps-page-break">';
    h += buildPsHeader("Upgrade Details");
    h += '<div style="'+secHdr+'">Part E &middot; Contract Upgrade Selections</div>';
    if(textLines.length > 0){
      h += '<div style="font-size:10px;line-height:1.7;margin-bottom:12px">';
      textLines.forEach(function(line){ h += '<div>&bull; '+esc(line)+'</div>'; });
      h += '</div>';
    } else {
      h += '<p style="font-size:11px;color:#777">No upgrades selected.</p>';
    }
    if(bullets.length > 0){
      h += '<div style="'+secHdrDk+'">Upgrade Pricing Breakdown</div>';
      h += '<table style="width:100%;border-collapse:collapse;font-size:10px">';
      h += '<thead><tr style="border-bottom:2px solid #333"><th style="text-align:left;padding:3px">Item</th><th style="text-align:right;padding:3px">Amount</th></tr></thead><tbody>';
      var bTotal = 0;
      bullets.forEach(function(b){
        bTotal += b.cost;
        var neg = b.cost < 0;
        h += '<tr style="border-bottom:1px solid #ddd"><td style="padding:3px">'+esc(b.label)+'</td><td style="text-align:right;padding:3px;font-family:monospace;'+(neg?'color:#065F46':'')+'">'+( neg ? '−'+fmt(Math.abs(b.cost)) : fmt(b.cost) )+'</td></tr>';
      });
      h += '<tr style="border-top:2px solid #333;font-weight:700"><td style="padding:4px 3px">GRAND TOTAL IN UPGRADES</td><td style="text-align:right;padding:4px 3px;font-family:monospace">'+fmt(bTotal)+'</td></tr></tbody></table>';
    }
    h += '<div style="margin-top:10px;font-size:9px;color:#999">Summertown Metals Contracting &bull; '+psDateStamp()+'</div>';
  }

  return h;
}

function buildPsUpgradeWording(){
  var h = buildPsHeader("Contract Upgrade Selections");
  var textLines = gatherUpgradeTextLines();
  if(textLines.length === 0){
    h += '<p style="font-size:13px;color:#777">No upgrades selected.</p>';
  } else {
    h += '<div style="font-size:12px;line-height:1.8;margin-top:10px">';
    textLines.forEach(function(line){ h += '<div>&bull; '+esc(line)+'</div>'; });
    h += '</div>';
  }
  h += '<div style="margin-top:16px;font-size:10px;color:#777">Summertown Metals Contracting &bull; '+psDateStamp()+'</div>';
  return h;
}

/* ═══════════════════════════════════════════════════════════════════════
   CANONICAL TURNKEY BANK CONTRACT — Sprint 2 request #6
   ═══════════════════════════════════════════════════════════════════════
   Renders the full word-for-word turnkey bank contract that goes to
   DocuSign / the lender. Modeled directly on the Leese 1/28/2026
   contract (uploaded by Alec as canonical reference).

   Structure (matches Leese):
     Page 1   — Header (logo, Order #, Bank), title, intro paragraph
                with $TOTAL, opening clauses (Proof of Funds, Permits,
                Change Orders, Site Preparation, Concrete Work, Building
                Methods, Additional Costs)
     Page 2   — Project Cost Itemized (full draw schedule with shop
                rows always visible per request #3)
     Page 3+  — Project Plans and Specification Notes (rep's free-text
                Notes, then paragraph break, then auto-generated upgrade
                list — Option A render-time concatenation per request #5)
     Pages 5-12 — Sections 1-42 boilerplate (verbatim from Leese)
     Page 13  — Disclaimer + Oil Canning + Substitution
     Page 14  — Signatures + STMC footer block

   Each function returns an HTML fragment to be wrapped in a .ps-page
   <div> by the caller. Content is plain HTML with inline styles to
   survive the print-to-PDF stylesheet stripping.

   Helper conventions:
     - All money fields render via fmtMoney() so $0.00 displays correctly
       for unused shop rows (per request #3).
     - All buyer-supplied text passes through esc() to prevent injection
       and to handle "&" / "<" in customer names properly.
     - All clause numbering matches the Leese contract exactly. Edits
       to legal language must match what STMC's legal team approved.

   DocuSign anchor tokens (for future server-side integration):
     - The signature lines on page 14 will eventually carry hidden
       \\sig_buyer\\, \\sig_cobuyer\\, \\sig_contractor\\ anchor strings.
       Not embedded yet — Aaron's Django backend will inject them when
       the DocuSign API integration goes live (Sprint 3).
   ═══════════════════════════════════════════════════════════════════════ */

/* Returns the resolved Contracts Rep display name for the contract footer.
   "sales_rep" key means the salesperson signs their own contracts. */
function resolveContractsRepName(){
  var c = STATE.customer || {};
  var key = c.contractsRep || "";
  if(!key) return "";
  if(key === "sales_rep"){
    // Salesperson signs as Contractor — resolve their display name.
    var spKey = c.rep || "";
    if(spKey === "custom") return c.customRepName || "";
    var sp = (typeof SALESPERSONS !== "undefined")
      ? SALESPERSONS.find(function(s){ return s.key === spKey; })
      : null;
    return sp ? sp.name : "";
  }
  var cr = (typeof CONTRACTS_REPS !== "undefined")
    ? CONTRACTS_REPS.find(function(r){ return r.key === key; })
    : null;
  return cr ? cr.name : "";
}

/* Salesperson display name resolver. Handles "custom" by returning the
   customRepName free-text field. */
function resolveSalespersonName(){
  var c = STATE.customer || {};
  var spKey = c.rep || "";
  if(!spKey) return "";
  if(spKey === "custom") return c.customRepName || "";
  var sp = (typeof SALESPERSONS !== "undefined")
    ? SALESPERSONS.find(function(s){ return s.key === spKey; })
    : null;
  return sp ? sp.name : spKey;
}

/* Resolves the job-site address as a single human-readable string for
   the contract intro paragraph ("for the property located at ..."). */
function resolveSiteAddressString(){
  var c = STATE.customer || {};
  var hasSite = !!((c.siteStreet || "").trim() || (c.siteCity || "").trim());
  var hasBill = !!((c.billStreet || "").trim() || (c.billCity || "").trim());
  if(hasSite){
    return [c.siteStreet, c.siteCity, c.siteState, c.siteZip]
      .filter(function(s){ return s && String(s).trim(); }).join(", ");
  }
  if(c.siteSameAsBilling && hasBill){
    return [c.billStreet, c.billCity, c.billState, c.billZip]
      .filter(function(s){ return s && String(s).trim(); }).join(", ");
  }
  return c.addr || "";
}

/* Format date as "M/D/YYYY" matching contract style (Leese: "1/28/2026"). */
function contractDateString(){
  var d = new Date();
  return (d.getMonth()+1) + "/" + d.getDate() + "/" + d.getFullYear();
}

/* Combines order number + secondary order number (for Ayer-style detached
   garage builds). Returns "0258711/025872" style when both present. */
function resolveOrderNumberString(){
  var c = STATE.customer || {};
  var primary = (c.order || "").trim();
  var secondary = (c.smOrderSecondary || "").trim();
  if(primary && secondary) return primary + "/" + secondary;
  return primary || secondary || "";
}

