function resolveContractsRep(){
  var key = STATE.customer.contractsRep || "";
  if(!key) return {name:"", email:""};
  var cr = (typeof CONTRACTS_REPS !== "undefined") ? CONTRACTS_REPS.find(function(r){ return r.key === key; }) : null;
  return cr ? {name: cr.name, email: cr.email || ""} : {name: key, email: ""};
}

function resolveJobSiteAddress(){
  var c = STATE.customer;
  var hasSite = !!((c.siteStreet||"").trim() || (c.siteCity||"").trim());
  var hasBill = !!((c.billStreet||"").trim() || (c.billCity||"").trim());
  if(hasSite) return [c.siteStreet, c.siteCity, c.siteState, c.siteZip].filter(Boolean).join(", ");
  if(c.siteSameAsBilling && hasBill) return [c.billStreet, c.billCity, c.billState, c.billZip].filter(Boolean).join(", ");
  return c.addr || "—";
}

/* DocuSign webhook handler — called by the backend when DocuSign Connect
   fires a status change event. Updates STATE.docusign and STATE.status.
   In the current tool, this is called via BACKEND.http polling or SSE.
   When Aaron's Django backend ships, it'll push via WebSocket. */
function handleDocuSignWebhook(event){
  if(!event || !event.type) return;
  STATE.docusign.webhookLastEvent = event.type;

  if(event.type === "envelope-completed"){
    STATE.status = "signed";
    STATE.docusign.signedAt = event.timestamp || new Date().toISOString();
    showToast("✓ Contract fully signed!");
  } else if(event.type === "envelope-voided"){
    STATE.status = "draft";
    STATE.docusign.voidedAt = event.timestamp || new Date().toISOString();
    showToast("⚠ Contract voided.");
  } else if(event.type === "recipient-completed"){
    // Update individual signer status
    if(event.signerEmail && STATE.docusign.signers){
      STATE.docusign.signers.forEach(function(s){
        if(s.email === event.signerEmail) s.status = "signed";
      });
    }
  } else if(event.type === "envelope-declined"){
    STATE.status = "draft";
    showToast("⚠ Signer declined — contract returned to draft.");
  }

  renderRunningTotal();
  scheduleSave();
}


/* ═══════════════════════════════════════════════════════════════════════
   CONTRACT PACKAGE SUBMISSION
   ───────────────────────────────────────────────────────────────────────
   The "Submit Contract Package" button is the final action in the wizard.
   It bundles everything for this customer/order into a single payload and
   sends it to the backend database. All documents are stored together
   and retrievable by order number.

   What gets submitted:
     1. Complete STATE snapshot (every field, selection, calculation)
     2. Contract PDF data (coordinates + customer data for server-side generation)
     3. DocuSign envelope (signer routing, tabs, custom fields)
     4. PM Budget (25 PO lines with cost codes and draw schedule)
     5. QB line items (trade-level with account mapping)
     6. Customer record (for QB Customer creation)
     7. Draw schedule (6-draw payment breakdown)

   The backend:
     - Assigns a packageId (UUID)
     - Stores the full STATE under the order number
     - Generates the contract PDF server-side (same coordinates)
     - Creates the DocuSign envelope and routes for signature
     - Creates the QB Customer + Estimate records
     - Returns the packageId for tracking

   When the backend is offline, the function still validates and shows
   exactly what would be submitted, then saves locally so the data is
   ready when the backend comes online.
   ═══════════════════════════════════════════════════════════════════════ */

function buildSubmissionChecklist(){
  var c = STATE.customer;
  var checks = [];

  // Customer
  checks.push({
    label: "Buyer name entered",
    ok: !!(c.name && c.name.trim()),
    detail: c.name || ""
  });
  checks.push({
    label: "Buyer email entered",
    ok: !!(c.email && c.email.trim()),
    detail: c.email || ""
  });
  checks.push({
    label: "S/M Order number entered",
    ok: !!(c.order && c.order.trim()),
    detail: c.order ? "#"+c.order : ""
  });
  checks.push({
    label: "Salesperson selected",
    ok: !!(c.rep),
    detail: c.rep === "custom" ? (c.customRepName || "(custom)") : (c.rep || "")
  });

  // Model + pricing
  checks.push({
    label: "Model selected",
    ok: !!STATE.model,
    detail: STATE.model || ""
  });
  checks.push({
    label: "Shell contract entered",
    ok: pn(STATE.shellContract) > 0,
    detail: pn(STATE.shellContract) > 0 ? fmt(STATE.shellContract) : ""
  });
  checks.push({
    label: "P10 material entered",
    ok: pn(c.p10) > 0,
    detail: pn(c.p10) > 0 ? fmt(c.p10) : ""
  });

  // Reconciliation
  var autoStatus = computeAutoStatus();
  checks.push({
    label: "Shell reconciled",
    ok: autoStatus === "reconciled" || autoStatus === "outForSig" || autoStatus === "signed",
    detail: autoStatus === "reconciled" ? "✓ balanced" : autoStatus
  });

  // Interior
  checks.push({
    label: "Living SF entered",
    ok: livSF() > 0,
    detail: livSF() > 0 ? $(livSF())+" SF" : ""
  });

  // Budget
  var extTotal = getExtLaborGrandTotal();
  checks.push({
    label: "Exterior labor budget entered",
    ok: extTotal > 0 || pmBudgetGrandTotal() > 0,
    detail: extTotal > 0 ? fmt(extTotal) : (pmBudgetGrandTotal() > 0 ? fmt(pmBudgetGrandTotal()) : "")
  });

  // Address
  var hasSite = !!((c.siteStreet||"").trim() || (c.siteCity||"").trim());
  var hasBill = !!((c.billStreet||"").trim() || (c.billCity||"").trim());
  checks.push({
    label: "Job site address entered",
    ok: hasSite || (c.siteSameAsBilling && hasBill) || !!(c.addr && c.addr.trim()),
    detail: hasSite ? (c.siteCity || c.siteStreet || "entered") : (c.siteSameAsBilling && hasBill ? "same as billing" : "")
  });

  return checks;
}

function buildSubmissionPayload(){
  var c = STATE.customer;
  var now = new Date();
  var orderNum = (c.order || "").trim();

  // Resolve salesperson display name
  var repDisplay = "";
  if(c.rep === "custom") repDisplay = c.customRepName || "Custom";
  else if(c.rep){
    var sp = SALESPERSONS.find(function(s){ return s.key === c.rep; });
    repDisplay = sp ? sp.name : c.rep;
  }

  return {
    // ── Identifiers ──
    orderNumber: orderNum,
    packageVersion: WIZ_VERSION,
    submittedAt: now.toISOString(),
    submittedBy: repDisplay,
    rateCardVersion: STATE.rateCardVersion || "built-in",

    // ── Customer Record (for QB Customer creation) ──
    customer: buildQBCustomer(),

    // ── Contract Summary ──
    contract: {
      model: STATE.model,
      branch: STATE.branch,
      branchLabel: BRANCHES[STATE.branch] ? BRANCHES[STATE.branch].label : STATE.branch,
      shellContract: pn(STATE.shellContract),
      concreteBudget: pn(STATE.concreteBudget),
      laborBudget: pn(STATE.laborBudget),
      p10: pn(c.p10),
      mft: getMFTMarkup(),
      interiorContract: computeInteriorContractPrice(),
      turnkeyTotal: computeTurnkeyTotal(),
      contractMeta: STATE.contractMeta || {},
      livingSF: livSF()
    },

    // ── Draw Schedule ──
    drawSchedule: computeDrawAmounts({
      isShell: false,
      p10WithMFT: pn(c.p10) + getMFTMarkup(),
      concTotal: pn(STATE.concreteBudget),
      custLabor: pn(STATE.laborBudget),
      intContract: computeInteriorContractPrice(),
      shellTotal: pn(STATE.shellContract)
    }),

    // ── DocuSign Envelope ──
    docusignEnvelope: buildDocuSignEnvelope(),

    // ── PM Budget (PO lines for the budget XLSX) ──
    budgetLines: buildPMBudgetRows(),

    // ── QB Line Items ──
    qbLineItems: buildQBLineItems(),

    // ── QB Estimate ──
    qbEstimate: buildQBEstimate(),

    // ── Exterior Labor Totals ──
    extLaborTotals: STATE.extLaborTotals || {},

    // ── Complete STATE Snapshot (every field preserved) ──
    stateSnapshot: STATE,

    // ── Checklist at time of submission ──
    checklist: buildSubmissionChecklist()
  };
}

function submitContractPackage(){
  // ── Validate ──
  var checklist = buildSubmissionChecklist();
  var failed = checklist.filter(function(c){ return !c.ok; });

  if(failed.length > 0){
    var msg = "The following items are incomplete:\n\n";
    failed.forEach(function(c, i){ msg += (i+1)+". "+c.label+"\n"; });
    msg += "\nSubmit anyway? (The package will be saved as incomplete — you can re-submit later once everything is filled in.)";
    if(!confirm(msg)) return;
  }

  // ── Build the full payload ──
  var payload = buildSubmissionPayload();
  var orderNum = payload.orderNumber || "(no order)";

  // ── Show confirmation ──
  var confirmMsg = "Submit Contract Package for:\n\n";
  confirmMsg += "  Buyer: " + (STATE.customer.name || "—") + "\n";
  confirmMsg += "  Order: " + orderNum + "\n";
  confirmMsg += "  Model: " + (STATE.model || "—") + "\n";
  confirmMsg += "  Total: " + fmt(computeTurnkeyTotal()) + "\n";
  confirmMsg += "  Budget Lines: " + payload.budgetLines.length + "\n";
  confirmMsg += "  QB Items: " + payload.qbLineItems.length + "\n\n";
  confirmMsg += "This will:\n";
  confirmMsg += "  1. Save contract + budget to the database\n";
  confirmMsg += "  2. Send the contract to DocuSign for signature\n";
  confirmMsg += "  3. Store all PDFs under order " + orderNum + "\n\n";
  confirmMsg += "Continue?";

  if(!confirm(confirmMsg)) return;

  // ── Update status ──
  if(!STATE.submission) STATE.submission = {};
  STATE.submission.status = "submitting";
  STATE.submission.error = "";
  STATE.submission.checklistSnapshot = {};
  checklist.forEach(function(c){ STATE.submission.checklistSnapshot[c.label] = c.ok; });
  STATE.submission.documentsIncluded = [
    "Contract PDF", "PM Budget XLSX", "QB Line Items",
    "Customer Upgrades", "Draw Schedule", "DocuSign Envelope"
  ];
  renderCurrentStep();

  // ── Submit to backend ──
  if(BACKEND.config.isEnabled()){
    BACKEND.http("POST", "/packages/submit", payload)
      .then(function(resp){
        STATE.submission.status = "submitted";
        STATE.submission.submittedAt = new Date().toISOString();
        STATE.submission.submittedBy = payload.submittedBy;
        STATE.submission.packageId = resp.packageId || "";
        STATE.status = "outForSig";
        showToast("✓ Contract package submitted — Package ID: "+(resp.packageId||"").substring(0,8)+"…");
        renderCurrentStep();
        scheduleSave();
      })
      .catch(function(err){
        STATE.submission.status = "error";
        STATE.submission.error = err.message || String(err);
        showToast("Submission failed: "+err.message);
        renderCurrentStep();
        scheduleSave();
      });
  } else {
    // ── Offline mode: save locally and guide manual workflow ──
    STATE.submission.status = "submitted";
    STATE.submission.submittedAt = new Date().toISOString();
    STATE.submission.submittedBy = payload.submittedBy;
    STATE.submission.packageId = "LOCAL-" + orderNum + "-" + Date.now();

    // Autosave the full state so nothing is lost
    doAutosave();

    showToast("📦 Package saved locally — "+STATE.submission.packageId);

    var offlineMsg = "Contract package saved locally (backend offline).\n\n";
    offlineMsg += "Package ID: "+STATE.submission.packageId+"\n\n";
    offlineMsg += "When the backend comes online:\n";
    offlineMsg += "  1. Click ⚙️ Backend to configure the connection\n";
    offlineMsg += "  2. Click ☁️ Cloud Save to push this job\n";
    offlineMsg += "  3. Re-click Submit to send the full package\n\n";
    offlineMsg += "For now, you can manually:\n";
    offlineMsg += "  • Click 'Save Contract as PDF' to generate the contract\n";
    offlineMsg += "  • Click 'Export PM Budget' to download the budget XLSX\n";
    offlineMsg += "  • Upload the PDF to DocuSign for manual signature routing\n";
    alert(offlineMsg);

    renderCurrentStep();
    scheduleSave();
  }
}

/* ═══════════════════════════════════════════════════════════════════════
   QUICKBOOKS INTEGRATION LAYER (Sprint 3)
   ───────────────────────────────────────────────────────────────────────
   Builds QB-ready data structures from STATE. When the backend is live,
   it receives these payloads and creates/updates QB records via the
   QB Online API.

   QB Record Flow:
     1. Customer — created/matched when contract is first saved to cloud
     2. Estimate — created from contract line items (pre-signature)
     3. Invoice  — created from Estimate after contract is signed
     4. Payment  — recorded as draws are received

   Account Mapping:
     Every budget line carries btCode (BuilderTrend) and qbAccount (QB)
     from the STMC_*_MAP tables. The buildQBLineItems() function walks
     the full budget and produces QB-ready line items with validated
     account references.
   ═══════════════════════════════════════════════════════════════════════ */

function validateQBMappings(){
  var warnings = [];
  var lineItems = buildQBLineItems();
  lineItems.forEach(function(li){
    if(!li.accountRef || !qbValidate(li.accountRef)){
      warnings.push(li.description + " → unmapped QB account '"+String(li.accountRef||"(none)")+"'");
    }
  });
  // Check customer type mapping
  var ct = STATE.customer.customerType || "individual";
  if(["individual","llc","trust"].indexOf(ct) < 0){
    warnings.push("Unknown customer type '"+ct+"' — QB customer record may need manual classification.");
  }
  return warnings;
}

function buildQBCustomer(){
  var c = STATE.customer;
  var siteAddr = resolveJobSiteAddress();
  var displayName = c.name || "(unnamed buyer)";
  if(c.coBuyerName) displayName += " & " + c.coBuyerName;

  return {
    DisplayName: displayName,
    GivenName: (c.name || "").split(" ")[0] || "",
    FamilyName: (c.name || "").split(" ").slice(1).join(" ") || "",
    PrimaryEmailAddr: { Address: c.email || "" },
    PrimaryPhone: { FreeFormNumber: c.phone || "" },
    CompanyName: c.customerType === "llc" ? c.name : "",
    CustomerType: c.customerType || "individual",
    // QB BillAddr
    BillAddr: {
      Line1: c.billStreet || "",
      City: c.billCity || "",
      CountrySubDivisionCode: c.billState || "TN",
      PostalCode: c.billZip || ""
    },
    // QB ShipAddr (job site)
    ShipAddr: {
      Line1: c.siteSameAsBilling ? (c.billStreet || "") : (c.siteStreet || ""),
      City: c.siteSameAsBilling ? (c.billCity || "") : (c.siteCity || ""),
      CountrySubDivisionCode: c.siteSameAsBilling ? (c.billState || "TN") : (c.siteState || "TN"),
      PostalCode: c.siteSameAsBilling ? (c.billZip || "") : (c.siteZip || "")
    },
    // STMC custom fields for QB
    Notes: "Model: "+(STATE.model||"?")+
           " | Branch: "+(BRANCHES[STATE.branch]?BRANCHES[STATE.branch].label:STATE.branch)+
           " | Order: "+(c.order||"?")+
           " | Bank: "+(c.bankName||"?")
  };
}

function buildQBLineItems(){
  var lines = [];
  var S = STATE;

  // 1. Shell Contract — P10 Material
  if(pn(S.customer.p10) > 0){
    var qb = qbForOther("P10 Material");
    lines.push({
      description: "P10 Material — " + (S.model || "Custom"),
      amount: pn(S.customer.p10),
      accountRef: qb ? qb.qbAccount : "",
      btCode: qb ? qb.btCode : "",
      category: "shell",
      drawNumber: 1
    });
  }

  // 2. MFT Markup (remote branches)
  var mft = getMFTMarkup();
  if(mft > 0){
    var qbMft = qbForOther("MFT Markup");
    lines.push({
      description: "Material Freight/Transit — " + Math.round((MFT_PCT[canonicalModel(S.model)]||0)*100) + "% on P10",
      amount: mft,
      accountRef: qbMft ? qbMft.qbAccount : "",
      btCode: qbMft ? qbMft.btCode : "",
      category: "shell",
      drawNumber: 1
    });
  }

  // 3. Concrete
  if(pn(S.concreteBudget) > 0){
    var qbConc = qbForOther("Concrete (pass-through)");
    lines.push({
      description: "Concrete Budget",
      amount: pn(S.concreteBudget),
      accountRef: qbConc ? qbConc.qbAccount : "",
      btCode: qbConc ? qbConc.btCode : "",
      category: "shell",
      drawNumber: 2
    });
  }

  // 4. Exterior Labor
  if(pn(S.laborBudget) > 0){
    var qbLabor = qbForOther("Customer Labor (preset)");
    lines.push({
      description: "Exterior Labor Budget",
      amount: pn(S.laborBudget),
      accountRef: qbLabor ? qbLabor.qbAccount : "",
      btCode: qbLabor ? qbLabor.btCode : "",
      category: "shell",
      drawNumber: 3
    });
  }

  // 5. Interior Base Turnkey Adder
  var intContract = computeInteriorContractPrice();
  if(intContract > 0){
    // Break interior into trade-level lines for QB granularity
    var isCustom = isCustomFloorPlan();

    // 5a. Base interior by trade group
    INT_TRADE_GROUPS.forEach(function(tg){
      var baseCost = calcIntTradeBase(tg);
      if(baseCost <= 0) return;
      var qbT = qbForTrade(tg.key);
      lines.push({
        description: "Interior — " + tg.name + " (base)",
        amount: baseCost,
        accountRef: qbT ? qbT.qbAccount : "",
        btCode: qbT ? qbT.btCode : "",
        category: "interior-base",
        tradeKey: tg.key,
        drawNumber: 4
      });
    });

    // 5b. CAD charges (cabinet LF, island, appliance config)
    computeCadCharges(S).forEach(function(c){
      var qbC = qbForTrade(c.trade);
      lines.push({
        description: "Interior CAD — " + c.label,
        amount: c.cost,
        accountRef: qbC ? qbC.qbAccount : "",
        btCode: qbC ? qbC.btCode : "",
        category: "interior-cad",
        tradeKey: c.trade,
        drawNumber: 4
      });
    });

    // 5c. Cabinet upgrades
    var cabT = computeCabSections(S);
    if(cabT.doorStyleTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Craftsman Door Style", amount: cabT.doorStyleTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.customCraftTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Custom Craftsman", amount: cabT.customCraftTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.kitchenTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Kitchen Addons", amount: cabT.kitchenTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.insertsTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Inserts", amount: cabT.insertsTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.laundryTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Laundry", amount: cabT.laundryTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.bathTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Bath", amount: cabT.bathTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.customTotal > 0){
      lines.push({ description: "Cabinet Upgrade — Custom Areas/Lines", amount: cabT.customTotal, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }
    if(cabT.discount > 0){
      lines.push({ description: "Cabinet Discount", amount: -cabT.discount, accountRef: "Cabinet Installation", btCode: "Cabinet Installation", category: "interior-upgrade", drawNumber: 5 });
    }

    // 5d. Countertop upgrades
    var ctT = computeCtSections(S);
    if(ctT.planCharge > 0 && !isCustom){
      lines.push({ description: "Countertop — Added SF Plan Charge", amount: ctT.planCharge, accountRef: "Countertops", btCode: "Countertops", category: "interior-upgrade", drawNumber: 5 });
    }
    if(ctT.areaUpgradesTotal > 0){
      lines.push({ description: "Countertop — Area Upgrades", amount: ctT.areaUpgradesTotal, accountRef: "Countertops", btCode: "Countertops", category: "interior-upgrade", drawNumber: 5 });
    }

    // 5e. Selection upgrades (Pills 1-5)
    ["docusign","electrical","plumbing","trim"].forEach(function(pillKey){
      var pillTotal = computeSelPillTotal(pillKey, S);
      if(pillTotal <= 0) return;
      // Walk items for per-line QB mapping
      var defs = SEL_DEFS[pillKey];
      if(!defs || !defs.sections) return;
      var sel = S.sel[pillKey];
      defs.sections.forEach(function(sec){
        (sec.items || []).forEach(function(it){
          var cost = computeSelItemCost(it, sel);
          if(cost <= 0) return;
          var qbU = qbForUpgrade(it.id, it.trade);
          lines.push({
            description: "Selection — " + it.label,
            amount: cost,
            accountRef: qbU ? qbU.qbAccount : "",
            btCode: qbU ? qbU.btCode : "",
            category: "interior-upgrade",
            tradeKey: it.trade,
            drawNumber: 4
          });
        });
        (sec.subsections || []).forEach(function(sub){
          (sub.items || []).forEach(function(it){
            var cost = computeSelItemCost(it, sel);
            if(cost <= 0) return;
            var qbU = qbForUpgrade(it.id, it.trade);
            lines.push({
              description: "Selection — " + it.label,
              amount: cost,
              accountRef: qbU ? qbU.qbAccount : "",
              btCode: qbU ? qbU.btCode : "",
              category: "interior-upgrade",
              tradeKey: it.trade,
              drawNumber: 4
            });
          });
        });
      });
    });

    // 5f. Custom upgrades (Pill 5)
    (S.sel && S.sel.custom && S.sel.custom.upgrades || []).forEach(function(r){
      var amt = r.pricing === "flat" ? pn(r.amount) : pn(r.rate) * pn(r.qty);
      if(amt <= 0) return;
      var qbU = qbForTrade(r.trade);
      lines.push({
        description: "Custom Upgrade — " + (r.desc || "(unnamed)"),
        amount: amt,
        accountRef: qbU ? qbU.qbAccount : "",
        btCode: qbU ? qbU.btCode : "",
        category: "interior-upgrade",
        tradeKey: r.trade,
        drawNumber: 5
      });
    });

    // 5g. Credits (Pill 5)
    (S.sel && S.sel.custom && S.sel.custom.credits || []).forEach(function(r){
      var amt = pn(r.amount);
      if(amt <= 0) return;
      var qbC = qbForTrade(r.trade);
      lines.push({
        description: "Credit — " + (r.desc || "(unnamed)"),
        amount: -amt,
        accountRef: qbC ? qbC.qbAccount : "",
        btCode: qbC ? qbC.btCode : "",
        category: "interior-credit",
        tradeKey: r.trade,
        drawNumber: 5
      });
    });
  }

  // 6. Detached Shop (if applicable)
  var shopMat = pn(STATE.contractMeta && STATE.contractMeta.detShopMaterial);
  var shopCL = pn(STATE.contractMeta && STATE.contractMeta.detShopConcLabor);
  if(shopMat > 0){
    lines.push({ description: "Shop/Detached Garage — Material", amount: shopMat, accountRef: "Materials", btCode: "Materials", category: "shop", drawNumber: 1 });
  }
  if(shopCL > 0){
    lines.push({ description: "Shop/Detached Garage — Concrete & Labor", amount: shopCL, accountRef: "Concrete", btCode: "Concrete Contract", category: "shop", drawNumber: 2 });
  }

  return lines;
}

function buildQBEstimate(){
  var customer = buildQBCustomer();
  var lineItems = buildQBLineItems();
  var total = computeTurnkeyTotal();

  return {
    CustomerRef: STATE.quickbooks.customerId || null,
    CustomerData: customer,   // Backend creates/matches customer first, then uses the ID
    TxnDate: new Date().toISOString().split("T")[0],
    ExpirationDate: null,     // Estimates don't expire (contracts do via DocuSign)
    DocNumber: STATE.customer.order || "",
    CustomerMemo: {
      value: "STMC Turnkey Contract — " + (STATE.model || "Custom Floor Plan") + " | " + resolveJobSiteAddress()
    },
    Line: lineItems.map(function(li, i){
      return {
        LineNum: i + 1,
        Description: li.description,
        Amount: li.amount,
        DetailType: "SalesItemLineDetail",
        SalesItemLineDetail: {
          ItemRef: { value: li.btCode || li.accountRef || "Services" },
          Qty: 1,
          UnitPrice: li.amount
        }
      };
    }),
    TotalAmt: total,
    // STMC custom fields for QB reporting
    PrivateNote: "Model: "+(STATE.model||"?")+" | Branch: "+(BRANCHES[STATE.branch]?BRANCHES[STATE.branch].label:STATE.branch)+" | Order: "+(STATE.customer.order||"?")+" | Rate Card: "+(STATE.rateCardVersion||"built-in")+" | "+WIZ_VERSION,
    ClassRef: STATE.quickbooks.classRef || (BRANCHES[STATE.branch] ? BRANCHES[STATE.branch].label : "")
  };
}

/* QB sync entry point — called from Step 8 or the footer */
function syncToQuickBooks(){
  if(!BACKEND.config.isEnabled()){
    showToast("Backend is offline. Enable cloud sync in ⚙️ Backend to push to QuickBooks.");
    return;
  }

  // Validate
  var warnings = validateQBMappings();
  if(warnings.length > 0){
    var msg = "QuickBooks mapping warnings:\n\n";
    warnings.forEach(function(w){ msg += "  · "+w+"\n"; });
    msg += "\nContinue anyway? (Unmapped lines will need manual QB entry.)";
    if(!confirm(msg)) return;
  }

  STATE.quickbooks.syncStatus = "syncing";
  STATE.quickbooks.syncError = "";
  renderCurrentStep();

  var estimate = buildQBEstimate();

  BACKEND.http("POST", "/quickbooks/estimate", estimate)
    .then(function(resp){
      STATE.quickbooks.customerId = resp.customerId || STATE.quickbooks.customerId;
      STATE.quickbooks.estimateId = resp.estimateId || "";
      STATE.quickbooks.syncedAt = new Date().toISOString();
      STATE.quickbooks.syncStatus = "synced";
      STATE.quickbooks.syncError = "";
      STATE.quickbooks.itemLines = buildQBLineItems();
      showToast("✓ QuickBooks estimate created — ID: "+(resp.estimateId||"?"));
      renderCurrentStep();
      scheduleSave();
    })
    .catch(function(err){
      STATE.quickbooks.syncStatus = "error";
      STATE.quickbooks.syncError = err.message || String(err);
      showToast("QB sync failed: "+err.message);
      renderCurrentStep();
      scheduleSave();
    });
}

/* Export line items as CSV (offline fallback for manual QB import) */
function exportQBLineItemsCSV(){
  var lines = buildQBLineItems();
  if(lines.length === 0){
    showToast("No line items to export — select a model and enter contract data first.");
    return;
  }
  var csv = "Description,Amount,QB Account,BT Code,Category,Draw #\n";
  lines.forEach(function(li){
    csv += '"'+String(li.description||"").replace(/"/g,'""')+'",';
    csv += li.amount+',';
    csv += '"'+String(li.accountRef||"").replace(/"/g,'""')+'",';
    csv += '"'+String(li.btCode||"").replace(/"/g,'""')+'",';
    csv += '"'+String(li.category||"").replace(/"/g,'""')+'",';
    csv += (li.drawNumber||"")+"\n";
  });

  var blob = new Blob([csv], {type:"text/csv"});
  var url = URL.createObjectURL(blob);
  var a = document.createElement("a");
  a.href = url;
  var custParts = [];
  if(STATE.customer.name) custParts.push(STATE.customer.name.trim());
  if(STATE.customer.order) custParts.push("#"+STATE.customer.order.trim());
  custParts.push("QB Line Items");
  custParts.push(new Date().getFullYear()+"-"+String(new Date().getMonth()+1).padStart(2,"0")+"-"+String(new Date().getDate()).padStart(2,"0"));
  custParts.push(WIZ_VERSION);
  a.download = custParts.join(" - ").replace(/[\\/:*?"<>|]+/g, "_") + ".csv";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast("Exported "+lines.length+" line items to CSV for QB import.");
}


/* ═══════════════════════════════════════════════════════════════════════
   PM BUDGET PURCHASE ORDER EXPORT (XLSX)
   ───────────────────────────────────────────────────────────────────────
   Generates an XLSX file matching the STMC PM Budget PO template.
   Fixed row order follows the construction draw schedule. Material costs
   (drywall, flooring, trim) are separated from installation labor.
   Each line carries a QB cost code and draw schedule number.

   Data sources (walked in PO order):
     1. PM Budget sections (exterior labor) — STATE.pmBudget
     2. Concrete budget — STATE.concreteBudget
     3. Interior trade groups — INT_TRADE_GROUPS × calcIntTradeBase
     4. Interior upgrades — cabinet, countertop, selection pills
     5. Detached shop (if applicable) — STATE.contractMeta

   Format matches PM_BUDGET_CSV_TEMPLATE.xlsx exactly:
     A: Job | B: PO # | C: Title | D: PO Status | E: Work Status
     F: Performed By | G: Created Date | H: Cost | I: Paid
     J: Cost Code | K: Variance Code | L: Est. Complete | M: Files | N: RFIs
   ═══════════════════════════════════════════════════════════════════════ */

function buildPMBudgetRows(){
  var S = STATE;
  var rows = [];
  var poNum = 1;
  // Job format: "Customer Name" OE1-"Order Number" (matches template)
  var custName = (S.customer.name || "Draft").trim();
  var orderNum = (S.customer.order || "").trim();
  var jobLabel = custName + (orderNum ? " OE1-" + orderNum : "");

  function add(title, cost, btCode, qbAccount, draw){
    rows.push({
      job: jobLabel,
      poNum: String(poNum).padStart(4, "0"),
      title: title,
      cost: Math.round(pn(cost) * 100) / 100,
      btCode: btCode || "",
      qbAccount: qbAccount || "",
      draw: draw || ""
    });
    poNum++;
  }

  var I = S.int || {};
  var upgradesByTrade = (typeof computeUpgradesByTrade === "function") ? computeUpgradesByTrade() : {};

  function rateCost(rateKey){
    var rc = INT_RC[rateKey]; if(!rc) return 0;
    var drivers = {
      livingSF: livSF(), garSF: garSF(), cabLF: pn(I.cabLF), counterSF: pn(I.counterSF),
      drywallSF: pn(I.drywallSF), trimLF: pn(I.trimLF), doors: pn(I.doors),
      bathCount: pi(I.fullBaths)+pi(I.halfBaths), fixtures: pn(I.fixtures)+getSelectionFixturePoints(S),
      hvacTons: pn(I.hvacTons), flat: 1
    };
    return rc.rate * (drivers[rc.driver] || 0);
  }
  function sumRates(keys){ var t=0; keys.forEach(function(k){ t+=rateCost(k); }); return t; }

  /* FIXED ROW ORDER — matches STMC_PM_BUDGET_TEMPLATE.xlsx exactly.
     ALL rows always output (even at $0). Every row has Job + PO#. */

  var ext = S.extLaborTotals || {};

  // Row 1: Concrete (Draw 2)
  add("Concrete", pn(S.concreteBudget), "Concrete", "Concrete", 2);
  // Rows 2-9: Exterior Labor (Draw 3)
  add("Framing",              pn(ext.framing),         "Whole House Framing", "Framing of Home", 3);
  add("Sheathing on Roof",    pn(ext.sheathingOnRoof), "Roofing",             "Roofing",         3);
  add("Roof",                 pn(ext.roof),             "Roof Labor",          "Framing of Home", 3);
  add("Metal Install",        pn(ext.walls),            "Siding",              "Metal Walls",     3);
  add("Rock",                 pn(ext.stone),            "Siding",              "Metal Walls",     3);
  add("Door and Window Install", pn(ext.doorsWindows),  "Whole House Framing", "Framing of Home", 3);
  add("Cupola",               pn(ext.cupola),           "Whole House Framing", "Framing of Home", 3);
  add("Decks/Porch",          pn(ext.decksPorch),       "Whole House Framing", "Framing of Home", 3);
  // Rows 6-9: Mechanical rough-in (Draw 4)
  add("Electrical",            rateCost("electrical") + (upgradesByTrade["electrical"]||0) + (upgradesByTrade["lighting"]||0), "Electrical Installation", "Electrical Installation", 4);
  add("Plumbing Installation", rateCost("plumbingLab") + (upgradesByTrade["plumbing"]||0), "Plumbing Installation", "Plumbing Installation", 4);
  add("HVAC",                  rateCost("hvac") + (upgradesByTrade["hvac"]||0), "HVAC", "HVAC", 4);
  add("Insulation",            sumRates(["insulation","insulGarage"]) + (upgradesByTrade["insulation"]||0), "Insulation - Spray Foam", "Insulation - Spray Foam", 4);
  // Rows 10-11: Drywall (Draw 5)
  add("Drywall Material",      rateCost("drywallMat"), "Drywall", "Drywall & Painting", 5);
  add("Drywall Installation",  rateCost("drywallLab") + (upgradesByTrade["drywall"]||0), "Drywall", "Drywall & Painting", 5);
  // Row 12: Painting (Draw 5)
  add("Painting", sumRates(["paint","paintExtDoor"]) + (upgradesByTrade["paint"]||0), "Painting", "Drywall & Painting", 5);
  // Rows 13-14: Cabinets + Countertops (Draw 5)
  add("Cabinets",     rateCost("cabinets") + (upgradesByTrade["cabinets"]||0), "Cabinets and Ctops", "Cabinets and Ctops", 5);
  // Countertops: use Excel base SF × 1.10 buffer × $43/SF for budget (not cabLF × 2)
  var ctBaseData = CT_BASE_SF[canonicalModel(S.model)] || {};
  var ctBaseSF = pn(ctBaseData.baseSF);
  var ctAddedSF = computeCtSections(S).addedSF;
  var ctBudgetSF = ctBaseSF > 0 ? Math.round(ctBaseSF * 1.10) + ctAddedSF : pn(I.counterSF);
  add("Countertops",  ctBudgetSF * 43 + (upgradesByTrade["countertops"]||0), "Cabinets and Ctops", "Cabinets and Ctops", 5);
  // Rows 15-16: Flooring (Draw 5)
  add("Flooring Materials",    rateCost("floorMat"), "Flooring", "Flooring", 5);
  add("Flooring Installation", rateCost("floorLab") + (upgradesByTrade["flooring"]||0), "Flooring", "Flooring", 5);
  // Rows 17-18: Trim & Doors (Draw 5)
  add("Trim and Door Materials",    rateCost("trimMat") + rateCost("doorMat"), "Interior Trim & Doors", "Interior Trim & Doors", 5);
  add("Trim and Door Installation", rateCost("trimDoorLab") + (upgradesByTrade["trim"]||0), "Interior Trim & Doors", "Interior Trim & Doors", 5);
  // Row 19: Fixtures (Draw 5)
  add("Plumbing & Light Fixtures", sumRates(["plumbFixBase","plumbFixBath","lightBase","lightBath"]), "Plumbing & Lighting Fixtures", "Plumbing & Lighting Fixtures", 5);
  // Row 20: Fireplace (Draw 5)
  add("Fireplace", upgradesByTrade["fireplaces"]||0, "Fireplace", "Fireplaces", 5);
  // Row 21: Tile (Draw 5)
  add("Tile", upgradesByTrade["tile"]||0, "Flooring", "Flooring", 5);
  // Rows 22-25: Close-out (Draw 6)
  add("Permits",                    pn(S.contractMeta && S.contractMeta.permitAllowance), "Permits", "Permits", 6);
  add("Final Clean",                rateCost("cleaning"), "Final Clean", "Final Cleaning", 6);
  add("Contract Allowance Expense", pn(S.contractMeta && S.contractMeta.sitePrepAllowance), "Contract Allowance", "Contract Allowance Expense", 6);
  add("Dumpster Allowance",         rateCost("dumpster"), "Waste Removal/Dumpster", "Waste Removal", 6);

  // Shop / Detached (appended after standard rows if applicable)
  var shopMat = pn(S.contractMeta && S.contractMeta.detShopMaterial);
  var shopCL = pn(S.contractMeta && S.contractMeta.detShopConcLabor);
  if(shopMat > 0) add("Shop/Detached Garage — Material", shopMat, "Materials", "Material Misc - For Completion", 1);
  if(shopCL > 0) add("Shop/Detached Garage — Concrete & Labor", shopCL, "Concrete", "Concrete", 2);

  return rows;
}

function exportPMBudgetXLSX(){
  var rows = buildPMBudgetRows();
  if(rows.length === 0){
    showToast("No budget data to export — enter exterior labor and interior data first.");
    return;
  }

  // ── Build filename matching the PDF convention ──
  // Format: "{Customer} - #{Order} - PM Budget - {YYYY-MM-DD} - {Version}.xlsx"
  var now = new Date();
  var custName = (STATE.customer.name || "Draft").trim();
  var orderNum = (STATE.customer.order || "").trim();
  var dateStr = now.getFullYear() + "-" + String(now.getMonth()+1).padStart(2,"0") + "-" + String(now.getDate()).padStart(2,"0");
  var parts = [];
  if(custName) parts.push(custName);
  if(orderNum) parts.push("#"+orderNum);
  parts.push("PM Budget");
  parts.push(dateStr);
  parts.push(WIZ_VERSION);
  var filename = parts.join(" - ").replace(/[\\/:*?"<>|]+/g, "_") + ".xlsx";


  // ── Sheet data ──
  var headers = ["Job", "PO #", "Title", "Cost", "BT Cost Code", "QB Account", "DRAW SCHEDULE"];
  var sheetData = [];

  // Title row
  sheetData.push(["Budget Detail", "", "", "", "", "", ""]);
  // Header row
  sheetData.push(headers);

  // Data rows
  var totalCost = 0;
  rows.forEach(function(r){
    totalCost += r.cost;
    sheetData.push([r.job, r.poNum, r.title, r.cost, r.btCode, r.qbAccount, r.draw ? String(r.draw) : ""]);
  });

  // Total row
  sheetData.push(["", "", "TOTAL BUDGETED", totalCost, "", "", ""]);

  // ── Generate XLSX or CSV fallback ──
  if(typeof XLSX !== "undefined"){
    var wb = XLSX.utils.book_new();
    var ws = XLSX.utils.aoa_to_sheet(sheetData);

    // Column widths matching template
    ws['!cols'] = [
      {wch: 41},  // A: Job
      {wch: 10},  // B: PO #
      {wch: 43},  // C: Title
      {wch: 16},  // D: Cost
      {wch: 28},  // E: BT Cost Code
      {wch: 32},  // F: QB Account
      {wch: 19}   // G: Draw Schedule
    ];

    // Merge title row A1:C1
    ws['!merges'] = [{s:{r:0,c:0}, e:{r:0,c:2}}];

    // Format cost cells as currency
    for(var r = 2; r < sheetData.length; r++){
      var costCell = XLSX.utils.encode_cell({r:r, c:3});
      if(ws[costCell] && typeof ws[costCell].v === "number") ws[costCell].z = '#,##0.00';
    }

    // Total row — use SUM formula
    var totalCell = XLSX.utils.encode_cell({r: sheetData.length-1, c: 3});
    ws[totalCell] = {t:'n', f:'SUM(D3:D'+(sheetData.length-1)+')', z:'#,##0.00'};

    XLSX.utils.book_append_sheet(wb, ws, "Purchase Orders");
    XLSX.writeFile(wb, filename);
    showToast("Exported "+rows.length+" lines to "+filename);
  } else {
    // CSV fallback
    var csv = sheetData.map(function(row){
      return row.map(function(cell){
        var s = String(cell == null ? "" : cell);
        return (s.indexOf(",")>=0||s.indexOf('"')>=0||s.indexOf("\n")>=0) ? '"'+s.replace(/"/g,'""')+'"' : s;
      }).join(",");
    }).join("\n");
    var blob = new Blob([csv], {type:"text/csv"});
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = filename.replace(/\.xlsx$/, ".csv");
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast("Exported "+rows.length+" lines to CSV (SheetJS offline).");
  }
}



/* ═══════════════════════════════════════════════════════════════════════
   STMC BANK CONTRACT — PDF OVERLAY GENERATOR (Sprint 2.5)
   ───────────────────────────────────────────────────────────────────────
   Replaces the HTML-print contract path with a coordinate-overlay
   approach. The cleaned 14-page bank-contract template is embedded as
   base64 below; pdf-lib (loaded from CDN at the top of <head>) opens it,
   stamps customer/job data at exact x/y coordinates, and saves out a
   byte-deterministic, pixel-exact contract PDF.

   - Pages 1–4: prefilled with data (envelope, order, bank, names, address,
     contract amount, 9-row draw schedule, project notes, interior upgrades)
   - Pages 5–14: untouched (static contract clauses + signature page)
   - Buyer initials, signatures, and signature dates: never overlaid here —
     DocuSign places those tabs at signing time

   To tune coordinates: edit STMC_BANK_CONTRACT_COORDINATES below and click
   the "🎯 Calibration PDF" button on Step 8 to see crosshairs at every
   field anchor.

   The same coordinate map and helper signatures port 1:1 to Python
   (pypdf + reportlab) when Aaron's Django backend takes over PDF
   generation in Sprint 3.
   ═══════════════════════════════════════════════════════════════════════ */

